const CALD_200 = [
  // ==================== EASY (60) ====================
  {id:"cald-001",d:"easy",t:"Growth and Development",q:"Which of the following best describes GROWTH?",c:["A. Qualitative changes in the organism as a whole","B. Quantitative changes in size, weight, and number","C. Changes that occur from womb to tomb","D. Changes in the quality of a person's skills"],a:"B",e:"Growth refers to quantitative, observable changes such as increases in size, weight, height, and number — things that can be measured."},
  {id:"cald-002",d:"easy",t:"Growth and Development",q:"Development is best described as:",c:["A. Changes that stop at the attainment of maturity","B. Changes limited to the physical aspects of the body","C. Qualitative changes in the organism as a whole, possible even without growth","D. Observable increases in a person's height and weight"],a:"C",e:"Development describes qualitative changes in the whole organism — it is a continuous process from womb to tomb and can occur even without physical growth."},
  {id:"cald-003",d:"easy",t:"Principles of Development",q:"Which principle of development states that each individual has a unique rate of development?",c:["A. Development follows an orderly sequence","B. The rate of development is unique in each individual","C. Early development is more critical than later development","D. Development is the product of maturation and learning"],a:"B",e:"Principle #2 states that the rate of development is unique in each individual — no two people develop at exactly the same pace."},
  {id:"cald-004",d:"easy",t:"Principles of Development",q:"The statement 'Early experiences serve as the foundation for later development' reflects which principle?",c:["A. Development involves change","B. Development follows an orderly sequence","C. Early development is more critical than later development","D. There are social expectations for every developmental period"],a:"C",e:"Principle #4 states that early development is more critical than later development — early experiences lay the foundation for all future growth."},
  {id:"cald-005",d:"easy",t:"Domains of Development",q:"Gross motor development involves:",c:["A. Small muscles such as fingers, lips, and tongue","B. The development of self-concept and self-esteem","C. Large muscles such as legs, arms, and the chest","D. Understanding and communicating using language"],a:"C",e:"Gross motor development refers to the large muscles in the body — legs, arms, and chest — used for activities like walking and running."},
  {id:"cald-006",d:"easy",t:"Domains of Development",q:"Which domain of development refers to thinking processes such as concentrating, problem-solving, and using logic?",c:["A. Physical Development","B. Social/Emotional Development","C. Language Development","D. Cognitive/Intellectual Development"],a:"D",e:"Cognitive/Intellectual Development includes thinking processes such as concentrating, imagining, problem-solving, using logic, and organizing information."},
  {id:"cald-007",d:"easy",t:"Stages of Human Development",q:"Which prenatal stage involves the creation of the zygote and takes place in the first two weeks after conception?",c:["A. Embryonic Period","B. Fetal Period","C. Germinal Period","D. Blastocyst Period"],a:"C",e:"The Germinal Period (0-2 weeks) involves the creation of the zygote, cell division, and attachment of the zygote to the uterine wall."},
  {id:"cald-008",d:"easy",t:"Stages of Human Development",q:"The stage of human development from birth to 2 weeks is called:",c:["A. Babyhood Stage","B. Infancy","C. Early Childhood","D. Prenatal Stage"],a:"B",e:"Infancy spans from birth to 2 weeks and is considered the shortest of all developmental periods, characterized by extreme helplessness."},
  {id:"cald-009",d:"easy",t:"Stages of Human Development",q:"Early Childhood (3 to 5 years old) is also called the:",c:["A. Gang age","B. Preschooler years","C. Toddler stage","D. Period of the Neonate"],a:"B",e:"Early Childhood (3-5 years) is called the 'preschooler years' — years before formal schooling begins."},
  {id:"cald-010",d:"easy",t:"Stages of Human Development",q:"Which stage is characterized by 'decreasing dependency' as babies gain enough body control?",c:["A. Infancy","B. Early Childhood","C. Babyhood Stage","D. Middle Childhood"],a:"C",e:"The Babyhood Stage (2 weeks to 2 years) is characterized by decreasing dependency as babies achieve enough body control to become more independent."},
  {id:"cald-011",d:"easy",t:"Stages of Human Development",q:"Adolescence spans from:",c:["A. 6-12 years","B. 13-18 years","C. 19-29 years","D. 30-60 years"],a:"B",e:"Adolescence spans from 13-18 years and is a transition age from childhood to adulthood marked by rapid physical changes and pursuit of identity."},
  {id:"cald-012",d:"easy",t:"Erikson's Psychosocial Theory",q:"Erikson's theory is based on the Epigenetic Principle, which states that we develop through:",c:["A. Random and unplanned personality changes throughout life","B. A predetermined unfolding of our personalities in eight stages","C. Learning from our environment without any biological influence","D. Social interaction alone without any internal developmental plan"],a:"B",e:"The Epigenetic Principle explains that we develop through a predetermined unfolding of our personalities in eight stages."},
  {id:"cald-013",d:"easy",t:"Erikson's Psychosocial Theory",q:"In Erikson's theory, a 'Syntonic' disposition refers to:",c:["A. A negative outcome of a psychosocial crisis","B. A positive disposition such as Trust","C. The failure to resolve a developmental crisis","D. An extreme negative outcome called Malignancy"],a:"B",e:"Syntonic refers to the positive disposition in each psychosocial crisis stage — for example, Trust in the first stage."},
  {id:"cald-014",d:"easy",t:"Erikson's Psychosocial Theory",q:"The virtue gained from successfully resolving the Trust vs. Mistrust stage is:",c:["A. Will","B. Purpose","C. Hope","D. Competence"],a:"C",e:"Hope is the virtue or psychosocial strength gained when the Trust vs. Mistrust stage is successfully managed in infancy."},
  {id:"cald-015",d:"easy",t:"Freud's Psychoanalytic Theory",q:"Which of Freud's stages of psychosexual development corresponds to ages 3 to 6?",c:["A. Oral Stage","B. Anal Stage","C. Phallic Stage","D. Latency Stage"],a:"C",e:"The Phallic Stage occurs from ages 3 to 6. During this stage, the pleasure or erogenous zone is the genitals."},
  {id:"cald-016",d:"easy",t:"Freud's Psychoanalytic Theory",q:"The component of personality that operates on the PLEASURE PRINCIPLE is the:",c:["A. Ego","B. Superego","C. Id","D. Conscious"],a:"C",e:"The Id operates on the pleasure principle — it focuses on immediate gratification of needs without regard for reality or consequences."},
  {id:"cald-017",d:"easy",t:"Freud's Psychoanalytic Theory",q:"The Superego is best described as:",c:["A. The part that seeks immediate pleasure","B. The part that balances Id and reality","C. The moral aspect that operates on the morality principle","D. The unconscious part that drives basic instincts"],a:"C",e:"The Superego develops near the end of the preschool years and embodies a person's moral aspect, operating on the morality principle and functioning like a conscience."},
  {id:"cald-018",d:"easy",t:"Piaget's Cognitive Development",q:"The Sensorimotor Stage spans from:",c:["A. Birth to 2 years","B. 2 to 7 years","C. 7 to 11 years","D. 11 years and above"],a:"A",e:"The Sensorimotor Stage spans from birth to 2 years (infancy to babyhood), when a child learns through senses and muscle movement."},
  {id:"cald-019",d:"easy",t:"Piaget's Cognitive Development",q:"Object Permanence is a key achievement of which Piagetian stage?",c:["A. Formal Operational Stage","B. Concrete Operational Stage","C. Preoperational Stage","D. Sensorimotor Stage"],a:"D",e:"Object Permanence — the understanding that objects still exist even when out of sight — is a milestone of the Sensorimotor Stage."},
  {id:"cald-020",d:"easy",t:"Piaget's Cognitive Development",q:"Which stage of cognitive development is characterized by symbolic function and egocentrism?",c:["A. Sensorimotor Stage","B. Preoperational Stage","C. Concrete Operational Stage","D. Formal Operational Stage"],a:"B",e:"The Preoperational Stage (2-7 years) is characterized by symbolic function, egocentrism, centration, lack of conservation, and irreversibility."},
  {id:"cald-021",d:"easy",t:"Vygotsky's Socio-Cultural Theory",q:"The Zone of Proximal Development (ZPD) is the difference between what a child can accomplish ALONE and what they can accomplish:",c:["A. With more practice and repetition","B. With the guidance of a more knowledgeable other","C. After completing formal schooling","D. Without any adult interference"],a:"B",e:"The ZPD is the difference between what a child can accomplish alone and what they can accomplish with the guidance of a knowledgeable adult or more advanced peer."},
  {id:"cald-022",d:"easy",t:"Vygotsky's Socio-Cultural Theory",q:"Scaffolding in Vygotsky's theory refers to:",c:["A. The natural maturation process of a child","B. Building physical structures in the classroom","C. Support or assistance that lets a child accomplish a task they cannot do independently","D. A child's ability to solve problems without any help"],a:"C",e:"Scaffolding is the support or assistance given by the MKO (More Knowledgeable Other) that lets the child accomplish tasks they cannot do independently."},
  {id:"cald-023",d:"easy",t:"Kohlberg's Moral Development",q:"Level I of Kohlberg's Moral Development is called:",c:["A. Conventional Morality","B. Post-Conventional Morality","C. Pre-Conventional Morality","D. Universal Ethical Morality"],a:"C",e:"Level I is Pre-Conventional Morality, where people do not really understand the conventions/rules of society."},
  {id:"cald-024",d:"easy",t:"Kohlberg's Moral Development",q:"In Kohlberg's Stage 1 (Punishment-Obedience Orientation), behavior is determined by:",c:["A. Social approval from peers","B. Consequences of acts — whether they lead to punishment or reward","C. The benefit to the individual","D. Universal ethical principles"],a:"B",e:"In Stage 1, consequences determine whether acts are good or bad — the child obeys rules to avoid punishment."},
  {id:"cald-025",d:"easy",t:"Bronfenbrenner's Ecological Theory",q:"The MICROSYSTEM in Bronfenbrenner's theory refers to:",c:["A. The outermost layer of cultural values and laws","B. The larger social system one step removed from the child","C. The layer closest to the child with direct contact structures like family","D. The historical and time dimension of a child's environment"],a:"C",e:"The Microsystem is the layer closest to the child and contains structures with which the child has direct contact — family, school, neighborhood."},
  {id:"cald-026",d:"easy",t:"Bronfenbrenner's Ecological Theory",q:"Which system in Bronfenbrenner's theory encompasses the dimension of TIME as it relates to a child's environments?",c:["A. Microsystem","B. Mesosystem","C. Exosystem","D. Chronosystem"],a:"D",e:"The Chronosystem encompasses the dimension of time — the social and historical time frame in which a child's life is set, reflecting how children change over time."},
  {id:"cald-027",d:"easy",t:"Behaviorism",q:"Who is known as the Father of Behaviorism?",c:["A. Ivan Pavlov","B. B.F. Skinner","C. John Watson","D. Edward Thorndike"],a:"C",e:"John Watson (1878-1958) is known as the Father of Behaviorism, famous for his belief in the power of conditioning and the stimulus-response theory."},
  {id:"cald-028",d:"easy",t:"Classical Conditioning",q:"In Pavlov's experiment, the FOOD (meat powder) served as the:",c:["A. Conditioned Stimulus","B. Unconditioned Stimulus","C. Conditioned Response","D. Unconditioned Response"],a:"B",e:"In Pavlov's experiment, the food (meat powder) was the Unconditioned Stimulus (UCS) — it consistently produced salivation naturally and automatically."},
  {id:"cald-029",d:"easy",t:"Classical Conditioning",q:"The salivation that occurs AFTER the bell has been associated with food is called the:",c:["A. Unconditioned Response","B. Unconditioned Stimulus","C. Conditioned Response","D. Conditioned Stimulus"],a:"C",e:"The Conditioned Response (CR) is the learned response — salivation that occurs after the bell (CS) has been associated with food (UCS)."},
  {id:"cald-030",d:"easy",t:"Operant Conditioning",q:"POSITIVE REINFORCEMENT involves:",c:["A. Removing something negative to increase a behavior","B. Adding something negative to decrease a behavior","C. Adding something positive to increase a response","D. Removing something positive to decrease a behavior"],a:"C",e:"Positive Reinforcement involves adding something positive to INCREASE a response. Example: A mother gives her son praise for doing homework."},
  {id:"cald-031",d:"easy",t:"Operant Conditioning",q:"B.F. Skinner coined the term 'operant conditioning' and believed one should focus on:",c:["A. The unconscious mind and repressed memories","B. External, observable causes of behavior","C. The internal thoughts and feelings of the learner","D. The biological maturation of the child"],a:"B",e:"Skinner believed in focusing on the external, observable causes of behavior rather than trying to unpack internal thoughts and motivations."},
  {id:"cald-032",d:"easy",t:"Bandura's Social Cognitive Theory",q:"Albert Bandura's theory is also known as:",c:["A. Classical Conditioning Theory","B. Operant Conditioning Theory","C. Social Learning Theory / Social Cognitive Theory","D. Psychoanalytic Theory"],a:"C",e:"Bandura's theory is known as Social Learning Theory or Social Cognitive Theory (neo-behaviorism) — people learn by observing and imitating others."},
  {id:"cald-033",d:"easy",t:"Bandura's Social Cognitive Theory",q:"Which of the following is an example of a SYMBOLIC model in Bandura's observational learning?",c:["A. A teacher demonstrating a science experiment","B. A parent showing a child how to cook","C. A book, recipe, manual, or module","D. A peer performing a skill in front of classmates"],a:"C",e:"Symbolic models are presented through oral or written symbols — examples include cookbooks, recipes, manuals, and modules."},
  {id:"cald-034",d:"easy",t:"Cognitivism",q:"Metacognition, coined by John Flavell, means:",c:["A. Learning through observation and imitation","B. Thinking about thinking / learning how to learn","C. Solving problems through trial and error","D. The unconscious processing of information"],a:"B",e:"Metacognition means 'thinking about thinking' — being aware of how you learn and evaluate the strategies you use."},
  {id:"cald-035",d:"easy",t:"Ausubel's Meaningful Learning",q:"An Advance Organizer in Ausubel's theory is best described as:",c:["A. A post-lesson summary given after instruction","B. An overview of the information to be covered given before the exposition","C. A test given to diagnose prior knowledge gaps","D. A reward system for completing learning tasks"],a:"B",e:"An Advance Organizer presents an overview of the information to be covered during the exposition — it activates prior knowledge and prepares learners."},
  {id:"cald-036",d:"easy",t:"Information Processing Theory",q:"The stage of memory that holds an exact copy of stimuli for a very short period of time is:",c:["A. Short-Term Memory","B. Long-Term Memory","C. Sensory Memory","D. Working Memory"],a:"C",e:"Sensory Memory is an information store that holds an exact copy of stimuli for a very short period (fractions of a second to about 3 seconds)."},
  {id:"cald-037",d:"easy",t:"Maslow's Hierarchy of Needs",q:"According to Maslow, which needs must be satisfied FIRST before a person can act unselfishly?",c:["A. Esteem Needs","B. Love and Belonging Needs","C. Safety Needs","D. Physiological Needs"],a:"D",e:"Physiological needs are at the base of Maslow's hierarchy and must be satisfied first — they include food, water, sleep, oxygen, and freedom of movement."},
  {id:"cald-038",d:"easy",t:"Maslow's Hierarchy of Needs",q:"Self-Actualization, as described by Maslow, is:",c:["A. The need for safety from physical and emotional attack","B. The need for love, belonging, and acceptance","C. The desire to become everything one is capable of becoming","D. The need for recognition and admiration from others"],a:"C",e:"Self-Actualization is the highest level of Maslow's hierarchy — the desire to become more and more what one is, to become everything one is capable of becoming."},
  {id:"cald-039",d:"easy",t:"Factors of Development",q:"MATURATION in development refers to:",c:["A. Learning through the environment and experience","B. The natural growth resulting from heredity","C. The influence of culture on a child's behavior","D. Deliberate practice and rehearsal of skills"],a:"B",e:"Maturation refers to the natural growth resulting from heredity — it is a biological process that unfolds automatically regardless of environmental input."},
  {id:"cald-040",d:"easy",t:"Factors of Development",q:"NURTURE in human development refers to:",c:["A. The genetic blueprint passed from parent to child","B. The biological unfolding of developmental stages","C. The environment in and through which growing takes place","D. The innate intelligence a person is born with"],a:"C",e:"Nurture refers to Environmental Influences — the in and through which the growing takes place, including family, culture, and experiences."},
  {id:"cald-041",d:"easy",t:"Stages of Human Development",q:"The THREE periods of the Prenatal Stage are:",c:["A. Germinal, Embryonic, and Fetal","B. Zygote, Blastocyst, and Fetus","C. Infancy, Babyhood, and Early Childhood","D. Pre-natal, Natal, and Post-natal"],a:"A",e:"The three periods of the Prenatal Stage are: (1) Germinal Period (0-2 weeks), (2) Embryonic Period (2-8 weeks), and (3) Fetal Period (2-9 months)."},
  {id:"cald-042",d:"easy",t:"Stages of Human Development",q:"Which life-support system connects the baby to the placenta through two arteries and one vein?",c:["A. Amnion","B. Trophoblast","C. Umbilical Cord","D. Endoderm"],a:"C",e:"The Umbilical Cord contains two arteries and one vein that connects the baby to the placenta."},
  {id:"cald-043",d:"easy",t:"Erikson's Psychosocial Theory",q:"The psychosocial crisis of TODDLERS (Autonomy vs. Shame and Doubt) results in the virtue of:",c:["A. Hope","B. Will / Determination","C. Purpose","D. Competence"],a:"B",e:"Willpower or Determination is the virtue gained from successfully resolving the Autonomy vs. Shame and Doubt stage during the toddler years."},
  {id:"cald-044",d:"easy",t:"Kohlberg's Moral Development",q:"Stage 3 of Kohlberg's theory is called:",c:["A. Punishment-Obedience Orientation","B. Instrumental Relativist Orientation","C. Good Boy-Nice Girl Orientation","D. Law and Order Orientation"],a:"C",e:"Stage 3 is the Good Boy-Nice Girl Orientation, where ethical decisions are based on concern for or the opinions of others — seeking social approval."},
  {id:"cald-045",d:"easy",t:"Piaget's Cognitive Development",q:"The CONCRETE OPERATIONAL STAGE (7-11 years) corresponds to which school level?",c:["A. Preschool years","B. Elementary school years","C. Junior high school years","D. Senior high school years"],a:"B",e:"The Concrete Operational Stage covers the elementary school years (7-11 years) — children can think logically but only in terms of concrete objects."},
  {id:"cald-046",d:"easy",t:"Behaviorism",q:"Edward Lee Thorndike is known as the Founder of:",c:["A. Classical Conditioning","B. Behavior Psychology / Connectionism","C. Social Learning Theory","D. Humanistic Psychology"],a:"B",e:"Edward Lee Thorndike is the Founder of Behavior Psychology and Connectionism — he focused on testing stimulus-response relationships and defined learning as habit formation."},
  {id:"cald-047",d:"easy",t:"Piaget's Cognitive Development",q:"In the FORMAL OPERATIONAL STAGE, children can now:",c:["A. Conserve number and volume for the first time","B. Think only in terms of concrete objects","C. Solve abstract problems and hypothesize","D. Achieve object permanence"],a:"C",e:"The Formal Operational Stage (11 years and above) is when thinking becomes more logical — children can now solve abstract problems and hypothesize."},
  {id:"cald-048",d:"easy",t:"Developmental Tasks",q:"A Developmental Task, according to Robert Havighurst, is a task that arises at a certain period and whose successful achievement leads to:",c:["A. Unhappiness and social disapproval","B. Failure and difficulty with later tasks","C. Happiness and success with later tasks","D. Dependence on adult guidance"],a:"C",e:"A Developmental Task's successful achievement leads to happiness and success with later tasks, while failure leads to unhappiness, social disapproval, and difficulty with later tasks."},
  {id:"cald-049",d:"easy",t:"Bronfenbrenner's Ecological Theory",q:"The MACROSYSTEM is comprised of:",c:["A. The connection between structures in the child's microsystem","B. Cultural values, customs, and laws","C. A parent's place of employment","D. The child's family and school"],a:"B",e:"The Macrosystem may be considered the outermost layer in the child's environment — it is comprised of cultural values, customs, and laws."},
  {id:"cald-050",d:"easy",t:"Freud's Psychoanalytic Theory",q:"The Ego operates using the:",c:["A. Pleasure Principle","B. Morality Principle","C. Reality Principle","D. Unconscious Principle"],a:"C",e:"The Ego emerges during toddler and preschooler years and operates using the Reality Principle — it considers consequences and reasons and considers the best response to situations."},
  {id:"cald-051",d:"easy",t:"Classical Conditioning",q:"EXTINCTION in classical conditioning refers to:",c:["A. The reappearance of a CR after a rest period","B. The gradual decrease in the strength of a CR when the UCS is no longer presented","C. The tendency for another stimulus to produce a response similar to the CR","D. The overall process by which an organism learns to associate two events"],a:"B",e:"Extinction is the gradual decrease in the strength or rate of a CR that occurs when the UCS is no longer presented."},
  {id:"cald-052",d:"easy",t:"Vygotsky's Socio-Cultural Theory",q:"Private Speech in Vygotsky's theory is:",c:["A. Speech used only in formal educational settings","B. A form of self-talk that guides the child's thinking and action","C. The language used between parent and child only","D. An early sign of a language disorder in young children"],a:"B",e:"Private Speech is a form of self-talk that guides the child's thinking and action — it is a key feature of Vygotsky's socio-cultural theory."},
  {id:"cald-053",d:"easy",t:"Maslow's Hierarchy of Needs",q:"ESTEEM NEEDS include:",c:["A. Food, water, and shelter","B. Safety from physical and emotional harm","C. Love, belonging, and acceptance from others","D. Self-esteem from competence and recognition from others"],a:"D",e:"Esteem Needs are of two types: self-esteem (from competence or mastery of tasks) and recognition/attention from others."},
  {id:"cald-054",d:"easy",t:"Information Processing Theory",q:"FORGETTING due to the inability to recall previously known information is called:",c:["A. Decay Theory","B. Retrieval Failure","C. Interference Theory","D. Sensory overload"],a:"B",e:"Retrieval Failure is forgetting due to the inability to recall information — the information is stored but cannot be retrieved."},
  {id:"cald-055",d:"easy",t:"Operant Conditioning",q:"NEGATIVE PUNISHMENT involves:",c:["A. Adding something positive to increase a behavior","B. Removing something negative to increase a behavior","C. Taking away a desired item after undesired behavior to decrease future responses","D. Adding an unpleasant stimulus after undesired behavior"],a:"C",e:"Negative Punishment includes TAKING AWAY/REMOVING a certain desired item after undesired behavior happens to decrease future responses. Example: Parent takes away a toy."},
  {id:"cald-056",d:"easy",t:"Stages of Human Development",q:"The FETAL PERIOD lasts from:",c:["A. Conception to 2 weeks","B. 2 weeks to 2 months","C. 2 months to birth (9 months)","D. Birth to 2 weeks"],a:"C",e:"The Fetal Period lasts from about 2 months after conception until 9 months when the infant is born — organs mature to the point where life can be sustained outside the womb."},
  {id:"cald-057",d:"easy",t:"Piaget's Cognitive Development",q:"Schema in Piaget's theory refers to:",c:["A. The process of fitting new experiences into existing knowledge","B. The cognitive structure by which individuals intellectually adapt to and organize their environment","C. The process of creating a new mental structure","D. The balance between assimilation and accommodation"],a:"B",e:"Schema is the cognitive structure (universal pattern of development) by which individuals intellectually adapt to and organize their environment to create meaning."},
  {id:"cald-058",d:"easy",t:"Bandura's Social Cognitive Theory",q:"The ATTENTION phase of observational learning means:",c:["A. The observer must physically practice the behavior","B. The observer must be motivated to perform the behavior","C. Mere exposure alone ensures acquisition — no active noticing needed","D. The observer must attend to and recognize the distinctive features of the model's response"],a:"D",e:"Attention is the first phase — mere exposure does not ensure acquisition; the observer must attend to and recognize the distinctive features of the model's response."},
  {id:"cald-059",d:"easy",t:"Erikson's Psychosocial Theory",q:"MALIGNANCY in Erikson's theory involves:",c:["A. Too much of the positive and too little of the negative aspect","B. Too little of the positive and too much of the negative aspect of the task","C. A perfect balance between the two opposing forces","D. Complete resolution of the psychosocial crisis"],a:"B",e:"Malignancy involves too little of the positive and too much of the negative aspect of the task. Example: A person who can't trust others at all."},
  {id:"cald-060",d:"easy",t:"Piaget's Cognitive Development",q:"ASSIMILATION in Piaget's theory is the process of:",c:["A. Creating a new schema when existing ones don't work","B. Achieving balance between assimilation and accommodation","C. Fitting new experience into an already existing schema","D. Organizing information into meaningful categories"],a:"C",e:"Assimilation is the process of fitting new experience into an existing created schema — using what you already know to understand something new."},

  // ==================== MODERATE (100) ====================
  {id:"cald-061",d:"moderate",t:"Growth and Development",q:"A child grows 5 centimeters taller over the summer. A teacher notices the child also became more patient and emotionally regulated. Which statement BEST distinguishes these two observations?",c:["A. Both are examples of growth since they are observable changes","B. The height increase is growth; the emotional regulation is development","C. The height increase is development; emotional regulation is growth","D. Both are examples of development since they occur continuously"],a:"B",e:"The height increase is a quantitative, measurable change = Growth. Emotional regulation is a qualitative change in the whole organism = Development."},
  {id:"cald-062",d:"moderate",t:"Principles of Development",q:"A teacher notices that students in the same Grade 3 class vary widely in their reading ability. This BEST illustrates which principle of development?",c:["A. Development follows an orderly and predictable sequence","B. Development involves change in all domains simultaneously","C. The rate of development is unique in each individual","D. Early development is more critical than later development"],a:"C",e:"The wide variation in reading ability within the same grade level illustrates Principle #2 — the rate of development is unique in each individual."},
  {id:"cald-063",d:"moderate",t:"Cephalocaudal and Proximodistal Patterns",q:"A baby first gains control of her head, then her trunk, and finally her legs. This follows which pattern of physical development?",c:["A. Proximodistal Pattern — from center to periphery","B. Cephalocaudal Pattern — from head to toe","C. Gross-to-Fine Motor Pattern — large muscles before small muscles","D. Lateralization Pattern — left before right"],a:"B",e:"The Cephalocaudal Pattern describes development from head (top) to toe (bottom). The baby gaining head control before trunk and leg control is a classic example."},
  {id:"cald-064",d:"moderate",t:"Cephalocaudal and Proximodistal Patterns",q:"A child first develops muscular control of the trunk and arms before gaining fine control of the fingers. This illustrates:",c:["A. Cephalocaudal Pattern","B. Gross-to-Fine Motor Development only","C. Proximodistal Pattern — from the trunk outward to the extremities","D. Sensorimotor development in Piaget's theory"],a:"C",e:"The Proximodistal Pattern describes development from the center (trunk) outward to the hands and fingers — muscular control of trunk and arms comes before fingers."},
  {id:"cald-065",d:"moderate",t:"Erikson's Psychosocial Theory",q:"A teenager constantly questions who she is, experiments with different roles, and feels uncertain about her place in society. According to Erikson, she is experiencing the crisis of:",c:["A. Intimacy vs. Isolation","B. Industry vs. Inferiority","C. Identity vs. Role Confusion","D. Initiative vs. Guilt"],a:"C",e:"Identity vs. Role Confusion is the crisis of adolescence — teens question who they are, experiment with roles, and seek to find a place in the community (Fidelity as the virtue)."},
  {id:"cald-066",d:"moderate",t:"Erikson's Psychosocial Theory",q:"A 40-year-old man is deeply invested in mentoring young professionals and contributing to the next generation. In Erikson's framework, he is successfully resolving:",c:["A. Intimacy vs. Isolation","B. Generativity vs. Stagnation","C. Integrity vs. Despair","D. Industry vs. Inferiority"],a:"B",e:"Generativity vs. Stagnation is the crisis of middle adulthood — it involves the desire to take care of other people and expanding personal and social involvement."},
  {id:"cald-067",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"A 4-year-old boy seems overly attached to his mother and views his father as a rival. Freud would attribute this to:",c:["A. The Electra Complex","B. Identification with the aggressor","C. The Oedipus Complex","D. Anal fixation and retentiveness"],a:"C",e:"The Oedipus Complex — boys develop an unconscious sexual desire for their mother and see their father as a rival for her affection during the Phallic Stage."},
  {id:"cald-068",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"An adult who is obsessed with cleanliness, perfectionism, and control may have experienced fixation in which of Freud's stages?",c:["A. Oral Stage — leading to oral receptive personality","B. Phallic Stage — leading to Oedipus/Electra Complex","C. Latency Stage — due to repressed sexual urges","D. Anal Stage — leading to Anal Retentive personality"],a:"D",e:"Anal Retentive personality develops from fixation in the Anal Stage — it is characterized by an obsession with cleanliness, perfection, and control."},
  {id:"cald-069",d:"moderate",t:"Piaget's Cognitive Development",q:"A 5-year-old child is shown two equal glasses of water, then the water from one is poured into a taller, thinner glass. The child says the taller glass has MORE water. This demonstrates:",c:["A. Irreversibility","B. Animism","C. Centration and Lack of Conservation","D. Egocentrism"],a:"C",e:"Centration (focusing on only one aspect — height) and Lack of Conservation (inability to realize that quantity remains unchanged despite appearance) are both illustrated here."},
  {id:"cald-070",d:"moderate",t:"Piaget's Cognitive Development",q:"A child believes that the moon is following her as she walks home at night. This is an example of:",c:["A. Animism — attributing human-like traits to inanimate objects","B. Centration — focusing on only one aspect","C. Egocentrism — assuming the world revolves around oneself","D. Artificialism — believing natural events are man-made"],a:"C",e:"Egocentrism is the tendency of a child to only see his point of view and assume that everyone else sees the same thing — like the moon 'following' her."},
  {id:"cald-071",d:"moderate",t:"Vygotsky's Socio-Cultural Theory",q:"A student can solve addition problems independently but cannot yet solve subtraction problems without teacher guidance. The subtraction skill represents the student's:",c:["A. Zone of Actual Development","B. Zone of Proximal Development","C. More Knowledgeable Other (MKO)","D. Level of scaffolding needed"],a:"B",e:"The Zone of Proximal Development (ZPD) is what the child can accomplish WITH guidance but not alone — it is the learning opportunity zone."},
  {id:"cald-072",d:"moderate",t:"Vygotsky's Socio-Cultural Theory",q:"A teacher begins by demonstrating a skill, then has students try with guidance, and eventually has them perform it independently. This follows Vygotsky's scaffolding levels in which order?",c:["A. You do, I watch → I do, you watch → I do, you help","B. I do, you watch → I do, you help → You do, I help → You do, I watch","C. You do, I help → You do, I watch → I do, you watch","D. I watch, you do → You do, I help → I do, you watch"],a:"B",e:"The four scaffolding levels are: (1) I do, you watch → (2) I do, you help → (3) You do, I help → (4) You do, I watch."},
  {id:"cald-073",d:"moderate",t:"Kohlberg's Moral Development",q:"A student follows school rules primarily to avoid getting detention. According to Kohlberg, this student is at:",c:["A. Stage 2 — Instrumental Relativist Orientation","B. Stage 3 — Good Boy-Nice Girl Orientation","C. Stage 4 — Law and Order Orientation","D. Stage 1 — Punishment-Obedience Orientation"],a:"D",e:"Stage 1 (Punishment-Obedience Orientation) — behavior is driven by avoiding punishment (detention). Consequences determine whether an act is good or bad."},
  {id:"cald-074",d:"moderate",t:"Kohlberg's Moral Development",q:"A person refuses to follow a law they consider unjust because it violates their own self-chosen ethical principles. This reflects:",c:["A. Stage 3 — Good Boy-Nice Girl Orientation","B. Stage 4 — Law and Order Orientation","C. Stage 5 — Social Contract Orientation","D. Stage 6 — Universal Ethical Principle Orientation"],a:"D",e:"Stage 6 (Universal Ethical Principle Orientation) — right is defined by the decision of conscience in accord with self-chosen ethical principles that are logically comprehensive, universal, and consistent."},
  {id:"cald-075",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"A child's academic performance is affected by her father's stressful workplace, even though the child never visits her father's office. This illustrates the influence of the:",c:["A. Microsystem","B. Mesosystem","C. Exosystem","D. Macrosystem"],a:"C",e:"The Exosystem has an INDIRECT impact on the child's development through its connection with the family unit — a parent's workplace is a classic example."},
  {id:"cald-076",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"The relationship between a child's teacher and the child's parents is an example of the:",c:["A. Microsystem","B. Mesosystem","C. Exosystem","D. Macrosystem"],a:"B",e:"The Mesosystem provides the connection BETWEEN structures in the child's microsystem — the teacher-parent relationship is a classic example."},
  {id:"cald-077",d:"moderate",t:"Classical Conditioning",q:"After being conditioned to fear a white rat, little Albert also began to fear white rabbits and white cotton. This is an example of:",c:["A. Extinction","B. Spontaneous Recovery","C. Stimulus Discrimination","D. Stimulus Generalization"],a:"D",e:"Stimulus Generalization is the tendency for another stimulus to produce a response similar to the CR — the greater the similarity between stimuli, the greater the possibility of generalization."},
  {id:"cald-078",d:"moderate",t:"Classical Conditioning",q:"A student was conditioned to feel anxious at the sound of the school bell (associated with a surprise quiz). After the teacher stopped giving surprise quizzes for a month, the anxiety disappeared. This is:",c:["A. Stimulus Discrimination","B. Spontaneous Recovery","C. Extinction","D. Acquisition"],a:"C",e:"Extinction is the gradual decrease in the strength of a CR when the UCS (surprise quiz) is no longer presented. The conditioned anxiety fades away."},
  {id:"cald-079",d:"moderate",t:"Operant Conditioning",q:"A teacher removes homework assignments when students perform well on class discussions, hoping to INCREASE class participation. This is an example of:",c:["A. Positive Reinforcement","B. Negative Punishment","C. Positive Punishment","D. Negative Reinforcement"],a:"D",e:"Negative Reinforcement involves REMOVING something negative (homework) to INCREASE a behavior (class participation). Removing an undesirable stimulus increases the target behavior."},
  {id:"cald-080",d:"moderate",t:"Operant Conditioning",q:"A student is given extra recess time for completing assignments on time. The extra recess time is a:",c:["A. Negative Reinforcement","B. Positive Punishment","C. Negative Punishment","D. Positive Reinforcement"],a:"D",e:"Positive Reinforcement — adding something positive (extra recess) to INCREASE a desired behavior (completing assignments on time)."},
  {id:"cald-081",d:"moderate",t:"Bandura's Social Cognitive Theory",q:"A child watches a cartoon hero save people and later pretends to be a hero when playing. According to Bandura, which phase of observational learning has occurred?",c:["A. Only Attention and Retention","B. Attention, Retention, and Motor Reproduction","C. All four phases: Attention, Retention, Motor Reproduction, and Motivational Process","D. Only the Motivational Process phase"],a:"B",e:"The child has paid Attention, encoded the behavior in memory (Retention), and physically reproduced the behavior (Motor Reproduction). The Motivational Process is not yet clearly indicated."},
  {id:"cald-082",d:"moderate",t:"Ausubel's Meaningful Learning",q:"A student learns that whales are mammals, not fish, and must reorganize her understanding of what a mammal is. This represents which process of meaningful learning?",c:["A. Derivative Subsumption","B. Correlative Subsumption","C. Superordinate Learning","D. Combinatorial Learning"],a:"B",e:"Correlative Subsumption — to accommodate new information, you have to alter or expand your concept. More valuable than derivative subsumption because it enriches the higher-level concept."},
  {id:"cald-083",d:"moderate",t:"Information Processing Theory",q:"A student knows her childhood friend's phone number even though she hasn't called in years but cannot immediately remember it without prompting. This is stored in which type of memory?",c:["A. Sensory Memory","B. Short-Term Memory (STM)","C. Subconscious / Preconscious Memory","D. Long-Term Memory (LTM)"],a:"C",e:"The Subconscious/Preconscious — this is the part we can reach if prompted but is not in our active conscious. It's right below the surface but still 'hidden' unless we search for it."},
  {id:"cald-084",d:"moderate",t:"Maslow's Hierarchy of Needs",q:"A student consistently disrupts class to get attention and to feel accepted by peers. Based on Maslow's hierarchy, which unmet need is likely driving this behavior?",c:["A. Physiological Needs","B. Safety Needs","C. Love and Belonging Needs","D. Esteem Needs"],a:"C",e:"Love and Belonging Needs — the student is seeking Inclusion (to be part of a group) and Affection (to love and be loved), which are components of this need level."},
  {id:"cald-085",d:"moderate",t:"Piaget vs. Vygotsky",q:"Piaget's theory is MORE INDIVIDUAL in focus while Vygotsky's is MORE SOCIAL. Which of the following BEST illustrates this difference?",c:["A. Piaget believed stages are universal; Vygotsky believed stages are culturally determined","B. Piaget emphasized language while Vygotsky emphasized physical maturation","C. Both theorists agreed that social interaction drives cognitive development","D. Piaget focused on environmental factors; Vygotsky focused on genetic factors"],a:"A",e:"Piaget believed in universal stages of cognitive development; Vygotsky did not propose stages but emphasized cultural factors and social interaction in cognitive development."},
  {id:"cald-086",d:"moderate",t:"Erikson's Psychosocial Theory",q:"A child in elementary school works hard to master academic tasks and feel capable. If she consistently fails and feels inferior to her peers, the likely negative outcome is:",c:["A. Role Confusion","B. Shame and Doubt","C. Inferiority — developing an Inertia disposition","D. Guilt — developing a Ruthlessness disposition"],a:"C",e:"Industry vs. Inferiority is the crisis of elementary school years. Failure leads to Inferiority and the Inertia maladaptation — those who suffer inferiority complexes and stop trying."},
  {id:"cald-087",d:"moderate",t:"Freud's Topographical Model",q:"The Oedipus and Electra Complexes are buried in the unconscious out of awareness due to extreme anxiety. This means they are stored in the:",c:["A. Conscious mind — all that we are aware of","B. Preconscious/Subconscious — accessible when prompted","C. Unconscious — influences thoughts/feelings/behavior without awareness","D. Ego — the reality-based component of personality"],a:"C",e:"The Unconscious contains the things Freud believed most influences us — buried complexes like Oedipus and Electra are driven down by extreme anxiety but still influence behavior."},
  {id:"cald-088",d:"moderate",t:"Piaget's Cognitive Development",q:"A child in the Concrete Operational Stage is shown 10 pennies in a row and 10 pennies clustered together. She correctly identifies both sets as having the same number. This demonstrates:",c:["A. Object Permanence","B. Egocentrism","C. Hypothetical-Deductive Reasoning","D. Conservation"],a:"D",e:"Conservation — the ability to know that certain properties of objects like number, mass, volume, or area do not change even if there is a change in appearance."},
  {id:"cald-089",d:"moderate",t:"Kohlberg's Moral Development",q:"A nurse follows hospital protocols strictly even when she personally disagrees, because she believes respect for authority and maintaining social order is important. This reflects:",c:["A. Stage 2 — Personal benefit","B. Stage 3 — Social approval","C. Stage 4 — Law and Order Orientation","D. Stage 5 — Social Contract"],a:"C",e:"Stage 4 (Law and Order Orientation) — right behavior consists in doing one's duty, showing respect for authority, and maintaining the given social order for its own sake."},
  {id:"cald-090",d:"moderate",t:"Classical Conditioning",q:"After extinction, the conditioned response (CR) reappears on its own after a rest period without further training. This is called:",c:["A. Stimulus Generalization","B. Stimulus Discrimination","C. Acquisition","D. Spontaneous Recovery"],a:"D",e:"Spontaneous Recovery — in CC, spontaneous recovery is the reappearance of a CR when the CS is presented, following a rest period after the CR appears to have been extinguished."},
  {id:"cald-091",d:"moderate",t:"Bandura's Social Cognitive Theory",q:"A student observes and remembers how to solve a math problem but does NOT perform it because she is not motivated to do so. According to Bandura, which phase is missing?",c:["A. Attention","B. Retention","C. Motor Reproduction","D. Motivational Process"],a:"D",e:"Motivational Process — although the observer acquires and retains the ability to perform the modeled behavior, there will be no overt performance unless conditions are favorable (motivation)."},
  {id:"cald-092",d:"moderate",t:"Developmental Tasks",q:"'Learning to get along with age mates' is a developmental task associated with which stage?",c:["A. Infancy and Early Childhood","B. Middle and Late Childhood (6-12 years)","C. Adolescence","D. Early Adulthood"],a:"B",e:"Learning to get along with age mates is a Developmental Task for Middle and Late Childhood (6-12 years) according to Havighurst."},
  {id:"cald-093",d:"moderate",t:"Developmental Tasks",q:"'Preparing for marriage and family life' is a developmental task for which stage?",c:["A. Middle Adulthood","B. Late Adulthood","C. Early Adulthood","D. Adolescence"],a:"D",e:"Preparing for marriage and family life is a Developmental Task of Adolescence according to Havighurst."},
  {id:"cald-094",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"A person who trusts everyone unconditionally and cannot believe that anyone would mean them harm exhibits which extreme in Erikson's first stage?",c:["A. Malignancy — Withdrawal","B. Maladaptation — Sensory Maladjustment","C. Maladaptation — overly trusting/gullible (Sensory Maladjustment)","D. Malignancy — complete inability to trust"],a:"C",e:"Maladaptation (Sensory Maladjustment) involves too much trust — being overly trusting and gullible, unable to believe anyone would mean them harm."},
  {id:"cald-095",d:"moderate",t:"Piaget's Cognitive Development",q:"The ability to arrange objects in a SERIES based on a single dimension (weight, size, volume) is called:",c:["A. Classification","B. Conservation","C. Decentering","D. Seriation"],a:"D",e:"Seriation is the ability to arrange things in a series based on one dimension such as weight, volume, size, etc. — a key achievement of the Concrete Operational Stage."},
  {id:"cald-096",d:"moderate",t:"Ausubel's Meaningful Learning",q:"A student already knows many examples of renewable energy but does not know the concept itself until it is formally taught. This reflects which type of meaningful learning?",c:["A. Derivative Subsumption","B. Correlative Subsumption","C. Superordinate Learning","D. Combinatorial Learning"],a:"C",e:"Superordinate Learning — the student already knew examples of the concept but did not know the concept itself until it was taught to them."},
  {id:"cald-097",d:"moderate",t:"Information Processing Theory",q:"According to the Atkinson-Shiffrin model, which of the following CORRECTLY describes how information moves through memory?",c:["A. Long-Term Memory → Short-Term Memory → Sensory Memory","B. Sensory Memory → Short-Term Memory → Long-Term Memory","C. Short-Term Memory → Sensory Memory → Long-Term Memory","D. Long-Term Memory → Sensory Memory → Short-Term Memory"],a:"B",e:"The correct flow in Atkinson-Shiffrin's model: Sensory Memory → Short-Term Memory (STM, where we consciously work on it) → Long-Term Memory (permanent storage)."},
  {id:"cald-098",d:"moderate",t:"Robert Gagne",q:"A teacher begins a lesson by showing a surprising video clip related to the topic. According to Gagne's Nine Events of Instruction, this is:",c:["A. Informing learners of the objective","B. Stimulating recall of prior learning","C. Gaining attention (Reception)","D. Presenting the stimulus"],a:"C",e:"Event #1 in Gagne's Nine Events of Instruction is Gaining Attention (Reception) — capturing the learner's interest before teaching begins."},
  {id:"cald-099",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"The death of a parent when a child is 8 years old is an element WITHIN which system of Bronfenbrenner's model?",c:["A. Mesosystem — between microsystem structures","B. Exosystem — indirect environmental influences","C. Macrosystem — cultural values and laws","D. Chronosystem — external events that occur with the aging of a child"],a:"D",e:"The Chronosystem encompasses events that occur with the aging of a child — the death of a parent at age 8 is an external element within this system."},
  {id:"cald-100",d:"moderate",t:"Maslow's Hierarchy of Needs",q:"According to Maslow, a teacher who cannot keep the classroom under control and frequently feels physically threatened at school is most likely struggling with which unmet need?",c:["A. Physiological Needs","B. Safety Needs","C. Esteem Needs","D. Self-Actualization"],a:"B",e:"Safety Needs include safety from physical attack, emotional attack, and invasion — a teacher feeling physically threatened in the classroom has unmet Safety Needs."},
  {id:"cald-101",d:"moderate",t:"Metacognition",q:"A student realizes that re-reading her notes isn't helping her remember material and switches to creating flashcards. This is an example of which metacognitive category?",c:["A. Person Variables — knowledge about how humans learn","B. Task Variables — knowledge about the nature of the task","C. Strategy Variables — awareness of strategy effectiveness and adjusting it","D. Meta-memory — awareness of memory strategies"],a:"C",e:"Strategy Variables involve awareness of the strategy you are using and evaluating whether it is effective — the student evaluated re-reading, found it ineffective, and switched strategies."},
  {id:"cald-102",d:"moderate",t:"Operant Conditioning",q:"A student is given a failing mark (negative consequence) after turning in plagiarized work. The failing mark is intended to DECREASE future plagiarism. This is:",c:["A. Negative Reinforcement","B. Positive Punishment","C. Negative Punishment","D. Positive Reinforcement"],a:"B",e:"Positive Punishment — ADDING a negative consequence (failing mark) after undesired behavior (plagiarism) to decrease future responses."},
  {id:"cald-103",d:"moderate",t:"Erikson's Psychosocial Theory",q:"A person in Late Adulthood (61+ years) who looks back on life with regret, bitterness, and a sense of failure is exhibiting which outcome of Erikson's final stage?",c:["A. Generativity — caring for the next generation","B. Integrity — accepting one's life as meaningful","C. Despair — contempt and disdain for life (Disdain maladaptation)","D. Stagnation — no longer allowing time for themselves"],a:"C",e:"In the Integrity vs. Despair stage, failure leads to Despair — a contempt of life, becoming very negative and appearing to hate life (Disdain maladaptation)."},
  {id:"cald-104",d:"moderate",t:"Piaget's Cognitive Development",q:"A teenager uses HYPOTHETICAL-DEDUCTIVE REASONING to figure out which combination of chemicals produces a yellow liquid in an experiment. This reflects which stage?",c:["A. Concrete Operational Stage","B. Preoperational Stage","C. Sensorimotor Stage","D. Formal Operational Stage"],a:"D",e:"Hypothetical-Deductive Reasoning — the ability to come up with different hypotheses about a problem and weigh data to make a judgment — is a hallmark of the Formal Operational Stage."},
  {id:"cald-105",d:"moderate",t:"Kohlberg's Moral Development",q:"A person believes that rules and laws represent agreements among people about behavior that benefits society. When laws no longer meet society's needs, rules can be changed. This reflects:",c:["A. Stage 4 — Law and Order","B. Stage 5 — Social Contract Orientation","C. Stage 6 — Universal Ethical Principles","D. Stage 3 — Good Boy-Nice Girl"],a:"B",e:"Stage 5 (Social Contract Orientation) — rules and laws represent agreements among people about behavior that benefits society, and can be changed when they no longer meet society's needs."},
  {id:"cald-106",d:"moderate",t:"Vygotsky's Socio-Cultural Theory",q:"Vygotsky emphasized that LANGUAGE serves TWO functions. What are they?",c:["A. Unconscious function and conscious function","B. Social function and individual function","C. Receptive function and expressive function","D. Cognitive function and emotional function"],a:"B",e:"Language has a social function (opening the door for learners to acquire knowledge that others already have) and an important individual function — it is also a tool for thought."},
  {id:"cald-107",d:"moderate",t:"Classical Conditioning",q:"A dog salivates to a bell but NOT to a tone of a different pitch, because the tone was never paired with food. This is an example of:",c:["A. Stimulus Generalization","B. Extinction","C. Spontaneous Recovery","D. Stimulus Discrimination"],a:"D",e:"Stimulus Discrimination — stimulus discrimination occurs when a person or animal responds to the CS only, but not to any other stimulus that is similar to the CS."},
  {id:"cald-108",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"A girl develops an unconscious sexual attraction toward her father and sees her mother as a rival. Freud called this:",c:["A. Oedipus Complex","B. Electra Complex","C. Castration Anxiety","D. Penis Envy leading to Identification"],a:"B",e:"The Electra Complex — girls may develop an unconscious sexual attraction towards their father. Freud said girls eventually identify with their mothers to resolve this complex."},
  {id:"cald-109",d:"moderate",t:"Developmental Tasks",q:"According to Havighurst, 'Adjusting to decreasing physical strength and health' is a developmental task of which stage?",c:["A. Middle Adulthood","B. Early Adulthood","C. Adolescence","D. Late Adulthood / Old Age"],a:"D",e:"Adjusting to decreasing physical strength and health is a Developmental Task of Later Maturity/Old Age (61 years and above) according to Havighurst."},
  {id:"cald-110",d:"moderate",t:"Behaviorism",q:"Watson's 'Experiment on Albert' demonstrated that:",c:["A. Children cannot be classically conditioned due to cognitive limitations","B. Fear responses cannot be unlearned once conditioned","C. A child can be conditioned to fear something through classical conditioning","D. Positive reinforcement is more effective than classical conditioning"],a:"C",e:"Watson conditioned little Albert to fear a white rat by pairing it with a loud noise — demonstrating that children can be classically conditioned to develop fear responses."},
  {id:"cald-111",d:"moderate",t:"Ausubel's Meaningful Learning",q:"Ausubel viewed learning as an ACTIVE PROCESS. Which of the following BEST reflects his view?",c:["A. Learners passively receive and store information from teachers","B. Learners make sense of their surroundings by integrating new knowledge with what they already know","C. Learning is most effective when it occurs through punishment and reward","D. The environment is the sole determinant of what and how a learner learns"],a:"B",e:"Ausubel viewed learning as an active process — learners make sense of their surroundings not simply by responding to the environment but by integrating new knowledge with what they already know."},
  {id:"cald-112",d:"moderate",t:"Piaget's Cognitive Development",q:"DEDUCTIVE REASONING — applying a general rule to a particular situation — is characteristic of which stage?",c:["A. Preoperational Stage","B. Sensorimotor Stage","C. Concrete Operational Stage","D. Formal Operational Stage"],a:"D",e:"Deductive Reasoning is the ability to think logically by applying a general rule to a particular situation — a hallmark of the Formal Operational Stage (11 years and above)."},
  {id:"cald-113",d:"moderate",t:"Stages of Human Development",q:"The EMBRYONIC PERIOD (2-8 weeks) is important because:",c:["A. The zygote attaches to the uterine wall for the first time","B. Cell differentiation intensifies and three layers (ectoderm, mesoderm, endoderm) develop","C. The infant is born and begins breathing independently","D. The fetus develops the ability to move and the mother can feel kicks"],a:"B",e:"During the Embryonic Period, cell differentiation intensifies — the three layers (endoderm, ectoderm, mesoderm) form and the organs begin to develop (organogenesis)."},
  {id:"cald-114",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"A cultural law that mandates free education for all children, including those with disabilities, affects the child's development MOST through which system?",c:["A. Microsystem","B. Mesosystem","C. Exosystem","D. Macrosystem"],a:"D",e:"The Macrosystem is comprised of cultural values, customs, and laws — a law mandating free education for all is a macrosystem-level influence."},
  {id:"cald-115",d:"moderate",t:"Maslow's Hierarchy of Needs",q:"A teacher creates a classroom where students feel safe to make mistakes and where their basic needs are addressed. According to Maslow, this PRIMARILY enables students to reach:",c:["A. Safety Needs only","B. Love and Belonging Needs only","C. Higher-order needs like Esteem and Self-Actualization","D. Physiological Needs"],a:"C",e:"When lower-order needs (physiological, safety, love/belonging) are met, students can focus on higher-order needs like Esteem and Self-Actualization — achieving their full potential."},
  {id:"cald-116",d:"moderate",t:"Erikson's Psychosocial Theory",q:"A person in Early Adulthood who avoids close relationships and feels isolated may be experiencing which Eriksonian maladaptation?",c:["A. Exclusion — tendency to isolate oneself from love, friendship, and community","B. Repudiation — rejecting the need for an identity","C. Withdrawal — characterized by depression and psychosis","D. Inertia — inferiority complex that stops one from trying"],a:"A",e:"Exclusion is the maladaptation of Intimacy vs. Isolation — the tendency to isolate oneself from love, friendship, and community, developing hatefulness in compensation for loneliness."},
  {id:"cald-117",d:"moderate",t:"Piaget's Cognitive Development",q:"ANALOGICAL REASONING — the ability to perceive the relationship in one instance and apply it to narrow down possible answers in similar problems — is a skill of which stage?",c:["A. Preoperational Stage","B. Concrete Operational Stage","C. Sensorimotor Stage","D. Formal Operational Stage"],a:"D",e:"Analogical Reasoning is a higher-order thinking skill that emerges in the Formal Operational Stage (11 years and above)."},
  {id:"cald-118",d:"moderate",t:"Social/Emotional Development",q:"Social/Emotional Development refers to the development of:",c:["A. Language comprehension and expression skills","B. Gross and fine motor skills","C. Thinking processes and use of logic","D. Self-concept, self-esteem, expressing feelings, and forming relationships"],a:"D",e:"Social/Emotional Development refers to the development of self-concept and self-esteem, as well as the ability to express feelings and form relationships with other people."},
  {id:"cald-119",d:"moderate",t:"Operant Conditioning",q:"A student who washes the dishes to avoid his mother's nagging is demonstrating:",c:["A. Positive Punishment","B. Positive Reinforcement","C. Negative Reinforcement","D. Negative Punishment"],a:"C",e:"Negative Reinforcement — Bob does the dishes (behavior) to AVOID his mother NAGGING (negative stimulus). Removing the negative stimulus increases the behavior."},
  {id:"cald-120",d:"moderate",t:"Metacognition",q:"Meta-ATTENTION, a component of metacognitive Strategy Variables, refers to:",c:["A. The ability to store and retrieve information efficiently","B. Awareness of memory strategies that work best for you","C. Awareness of specific strategies to keep your attention focused on the topic or task","D. Knowledge about how human beings process information"],a:"C",e:"Meta-attention is the awareness of specific strategies so that you can keep your attention focused on the topic or task — a subcategory of Strategy Variables."},
  {id:"cald-121",d:"moderate",t:"Stages of Human Development",q:"Which of the following is NOT a life-support system for the embryo?",c:["A. Placenta","B. Umbilical Cord","C. Amnion","D. Blastocyst"],a:"D",e:"The Blastocyst is NOT a life-support system — it is the inner layer of cells in the Germinal Period that develops into the embryo. The three life-support systems are: Placenta, Umbilical Cord, and Amnion."},
  {id:"cald-122",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"A student who constantly needs to borrow pens, chews on pencils, smokes cigarettes, and tends to overeat may be showing signs of fixation in which stage?",c:["A. Anal Stage — anal expulsive personality","B. Phallic Stage — unresolved Oedipus Complex","C. Oral Stage — oral receptive personality","D. Latency Stage — repressed sexual urges"],a:"C",e:"Oral Receptive personality — fixation in the Oral Stage leads to a stronger tendency to smoke, drink alcohol, overeat, and engage in other oral activities."},
  {id:"cald-123",d:"moderate",t:"Vygotsky's Socio-Cultural Theory",q:"The key difference between Piaget and Vygotsky regarding cognitive development is that Vygotsky:",c:["A. Believed cognitive development occurs in universal, fixed stages","B. Gave little emphasis to the role of language in cognitive development","C. Stressed the role of language and social interaction in cognitive development","D. Believed individual maturation is more important than social factors"],a:"C",e:"Vygotsky stressed the role of LANGUAGE and SOCIAL INTERACTION in cognitive development, while Piaget gave little emphasis on language and focused more on individual maturation."},
  {id:"cald-124",d:"moderate",t:"Robert Gagne",q:"According to Gagne's Nine Events of Instruction, 'Providing feedback' corresponds to which instructional event?",c:["A. Eliciting performance (responding)","B. Enhancing retention and transfer","C. Providing feedback (reinforcement)","D. Stimulating recall of prior learning"],a:"C",e:"Gagne's Event #7 is Providing feedback (reinforcement) — giving information about the correctness of the learner's performance after they have responded."},
  {id:"cald-125",d:"moderate",t:"Behaviorism",q:"Thorndike's LAWS OF LEARNING include which of the following?",c:["A. Law of Effect, Law of Exercise, Law of Readiness","B. Law of Conditioning, Law of Extinction, Law of Recovery","C. Law of Reinforcement, Law of Punishment, Law of Extinction","D. Law of Assimilation, Law of Accommodation, Law of Equilibration"],a:"A",e:"Thorndike proposed the Law of Effect (reward strengthens connections), Law of Exercise (practice strengthens connections), and Law of Readiness (preparedness to learn)."},
  {id:"cald-126",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"Which Freudian concept explains why two siblings raised in the same household can have very different personalities?",c:["A. The Unconscious stores different repressed experiences for each child","B. Different fixation points in the stages of psychosexual development shape personality differently","C. The Superego develops at different times due to different moral instruction","D. The Ego uses different defense mechanisms for each child"],a:"B",e:"Different fixation points — each child experiences different levels of frustration or gratification at each psychosexual stage, leading to different personality outcomes."},
  {id:"cald-127",d:"moderate",t:"Developmental Tasks",q:"'Achieving new and more mature relations with age mates of both sexes' is a developmental task of:",c:["A. Middle and Late Childhood","B. Early Adulthood","C. Adolescence","D. Middle Adulthood"],a:"C",e:"Achieving new and more mature relations with age mates of both sexes is a Developmental Task of the Adolescence stage (13-18 years) according to Havighurst."},
  {id:"cald-128",d:"moderate",t:"Piaget's Cognitive Development",q:"ACCOMMODATION in Piaget's theory occurs when:",c:["A. New experiences are fitted into existing schemas","B. Balance is achieved between existing and new knowledge","C. A new schema is created to handle experiences that don't fit existing schemas","D. The child ignores information that contradicts existing schemas"],a:"C",e:"Accommodation is the process of CREATING A NEW SCHEMA when existing schemas don't work for a new experience — it involves a more thorough cognitive change."},
  {id:"cald-129",d:"moderate",t:"Erikson's Psychosocial Theory",q:"FIDELITY — the ability to live by society's standards and to have found a place in the community — is the virtue of which Eriksonian stage?",c:["A. Industry vs. Inferiority","B. Initiative vs. Guilt","C. Autonomy vs. Shame and Doubt","D. Identity vs. Role Confusion"],a:"D",e:"Fidelity is the virtue gained from successfully resolving the Identity vs. Role Confusion stage during Adolescence."},
  {id:"cald-130",d:"moderate",t:"Ausubel's Meaningful Learning",q:"A student learns about 'democracy' and then, while studying history, realizes that ancient Athens practiced a form of government that he can now identify as democracy. This reflects:",c:["A. Correlative Subsumption","B. Combinatorial Learning","C. Derivative Subsumption","D. Superordinate Learning"],a:"C",e:"Derivative Subsumption — the new information (ancient Athenian government) is an instance or example of a concept (democracy) the student has already learned."},
  {id:"cald-131",d:"moderate",t:"Maslow's Hierarchy of Needs",q:"A brilliant student refuses to participate in class because she fears being laughed at by peers if she gives a wrong answer. According to Maslow, which need is at risk?",c:["A. Physiological Needs","B. Safety Needs","C. Esteem Needs — specifically self-esteem","D. Love and Belonging Needs"],a:"C",e:"Esteem Needs — specifically self-esteem (the result of competence or mastery of tasks) and the fear of losing attention/recognition from others. The student fears damaging her self-esteem."},
  {id:"cald-132",d:"moderate",t:"Kohlberg's Moral Development",q:"A student cheats on a test only when he knows he won't be caught. His decision is based primarily on the BENEFIT to himself. This reflects:",c:["A. Stage 1 — Punishment-Obedience Orientation","B. Stage 2 — Instrumental Relativist Orientation","C. Stage 3 — Good Boy-Nice Girl Orientation","D. Stage 4 — Law and Order Orientation"],a:"B",e:"Stage 2 (Instrumental Relativist Orientation) — 'What's in it for me?' ethics — obeying rules and exchanging favors are judged in terms of benefit to the individual."},
  {id:"cald-133",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"A 10-year-old child raised during a period of national economic crisis shows heightened anxiety and resource-scarcity mindset that persists into adulthood. This is BEST explained by the:",c:["A. Microsystem — immediate family environment","B. Exosystem — indirect environmental influences","C. Macrosystem — cultural and economic systems","D. Chronosystem — historical time frame in which the child's life is set"],a:"D",e:"The Chronosystem reflects how children change over time and the social and historical time frame of their lives — an economic crisis experienced in childhood is a chronosystem event."},
  {id:"cald-134",d:"moderate",t:"Information Processing Theory",q:"A student studies the night before an exam and scores well. Six months later, she cannot recall most of what she learned. This is BEST explained by:",c:["A. Retrieval Failure — the information was never stored","B. Interference Theory — other learning blocked the information","C. Decay Theory — information stored in LTM gradually fades when not in use","D. Sensory Memory limitation — information was only briefly encoded"],a:"C",e:"Decay Theory — information on the LTM, if not rehearsed, can be forgotten. The student stored information but did not rehearse it, so it gradually faded."},
  {id:"cald-135",d:"moderate",t:"Piaget's Cognitive Development",q:"A preoperational child uses a banana as a 'telephone' during play. This demonstrates:",c:["A. Conservation","B. Object Permanence","C. Symbolic Function","D. Centration"],a:"C",e:"Symbolic Function — Preoperational children can represent objects and events symbolically. Using a banana as a telephone shows the ability to represent one thing with another."},
  {id:"cald-136",d:"moderate",t:"Erikson's Psychosocial Theory",q:"The FANATICISM maladaptation in Erikson's Identity stage is characterized by:",c:["A. Rejecting their membership in the world of adults","B. His way is the only way — gathering others to promote their beliefs without regard to others' rights","C. Overly trusting and gullible behavior","D. Compulsiveness — feeling everything must be done perfectly"],a:"B",e:"Fanaticism (maladaptation of Identity stage) — His way is the only way. He gathers around others and promotes their beliefs and lifestyles without regards to others' rights to disagree."},
  {id:"cald-137",d:"moderate",t:"Classical Conditioning",q:"In Pavlov's classical conditioning, ACQUISITION refers to:",c:["A. The gradual disappearance of the CR","B. The reappearance of the CR after rest","C. The overall process during which the organism learns to associate two events","D. The discrimination between similar stimuli"],a:"C",e:"Acquisition is the overall process during which the organism learns to associate two events (CS + UCS) — it is the initial learning of the conditioned response."},
  {id:"cald-138",d:"moderate",t:"Stages of Human Development",q:"The MESODERM layer of the embryo develops into:",c:["A. Digestive and respiratory systems","B. Nervous system, sensory receptors, and skin parts","C. Circulatory, skeletal, muscular, excretory, and reproductive systems","D. Brain, spinal cord, and peripheral nervous system"],a:"C",e:"The Mesoderm (middle layer) develops into the circulatory, skeletal, muscular, excretory, and reproductive systems (CREAMS: Circulatory, Reproductive, Excretory, Abdominal/muscular, Musculoskeletal)."},
  {id:"cald-139",d:"moderate",t:"Behaviorism",q:"Which of the following BEST distinguishes Classical Conditioning from Operant Conditioning?",c:["A. Classical conditioning uses rewards; operant conditioning uses neutral stimuli","B. Classical conditioning focuses on elicited reflexive responses; operant conditioning focuses on voluntary behaviors and their consequences","C. Classical conditioning was developed by Skinner; operant conditioning by Pavlov","D. Classical conditioning only applies to animals; operant conditioning applies to humans only"],a:"B",e:"Classical Conditioning focuses on elicited (reflexive) responses paired with neutral stimuli. Operant Conditioning focuses on voluntary behaviors and the consequences that follow them."},
  {id:"cald-140",d:"moderate",t:"Developmental Tasks",q:"'Managing home and taking on civic responsibility' are developmental tasks associated with:",c:["A. Adolescence","B. Middle Adulthood","C. Early Adulthood (19-29 years)","D. Late Adulthood"],a:"C",e:"Managing home and taking on civic responsibility are Developmental Tasks of Early Adulthood (19-29 years) — an age of adjustment to new patterns of life and new roles."},
  {id:"cald-141",d:"moderate",t:"Piaget's Cognitive Development",q:"A child is unable to imagine that the process of breaking a cookie into pieces can be reversed to make it whole again. This demonstrates:",c:["A. Lack of Conservation","B. Centration","C. Irreversibility","D. Animism"],a:"C",e:"Irreversibility — Preoperational children still have the inability to reverse their thinking. They cannot mentally 'undo' a physical action."},
  {id:"cald-142",d:"moderate",t:"Vygotsky's Socio-Cultural Theory",q:"A peer tutoring program where advanced students help struggling classmates is MOST consistent with which Vygotskian concept?",c:["A. Schema and Accommodation","B. Classical Conditioning and Reinforcement","C. Zone of Proximal Development and scaffolding with More Knowledgeable Other (MKO)","D. Formal Operational reasoning and abstract thinking"],a:"C",e:"Peer tutoring is consistent with Vygotsky's ZPD and MKO — advanced peers serve as More Knowledgeable Others, providing scaffolding to help struggling classmates grow within their ZPD."},
  {id:"cald-143",d:"moderate",t:"Piaget's Cognitive Development",q:"INDUCTIVE REASONING — from specific to general, drawing conclusions based on examples — is characteristic of:",c:["A. Formal Operational Stage only","B. Sensorimotor Stage","C. Concrete Operational Stage","D. Preoperational Stage"],a:"C",e:"Inductive Reasoning (from specific to general — conclusions based on examples) is a key achievement of the Concrete Operational Stage. Formal Operational adds Deductive Reasoning."},
  {id:"cald-144",d:"moderate",t:"Maslow's Hierarchy of Needs",q:"Abraham Maslow is associated with which psychological tradition?",c:["A. Behaviorism — Third Force","B. Psychoanalysis — Second Force","C. Humanistic Psychology — Third Force","D. Cognitivism — Fourth Force"],a:"C",e:"Abraham Maslow was a leading Humanistic Psychologist — Humanistic Psychology is called the Third Force (after Behaviorism and Psychoanalysis)."},
  {id:"cald-145",d:"moderate",t:"Kohlberg's Moral Development",q:"Kohlberg based much of his theory on the work of:",c:["A. Erik Erikson and Sigmund Freud","B. Jean Piaget and John Dewey","C. Lev Vygotsky and Albert Bandura","D. Abraham Maslow and Carl Rogers"],a:"B",e:"Kohlberg studied moral reasoning with much of his work based on that of Jean Piaget and John Dewey."},
  {id:"cald-146",d:"moderate",t:"Information Processing Theory",q:"The type of transfer where a person is able to learn more advanced or complex skills based on prior learning is called:",c:["A. Lateral Transfer","B. Specific Transfer","C. Vertical Transfer","D. General Transfer"],a:"C",e:"Vertical Transfer occurs when the individual is able to learn more advanced or complex skills based on prior learning at a lower level."},
  {id:"cald-147",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"A child resolves the Oedipus Complex by identifying with the same-sex parent and repressing sexual feelings toward the opposite-sex parent. The resolution results in the development of:",c:["A. The Id's pleasure-seeking drives","B. The Ego's reality principle","C. The Superego and conscience","D. The Unconscious and repression"],a:"C",e:"By identifying with the same-sex parent, the child internalizes their moral values and standards — this forms the Superego (conscience) and helps develop gender identity."},
  {id:"cald-148",d:"moderate",t:"Piaget's Cognitive Development",q:"A child believes that the clouds are alive because they move. This is an example of:",c:["A. Artificialism — believing natural events are man-made","B. Realism — believing psychological events like dreams are real","C. Animism — attributing human-like traits to inanimate objects","D. Egocentrism — seeing only from one's own point of view"],a:"C",e:"Animism is the tendency of the child to attribute human-like traits (like being alive because of movement) to inanimate objects — a characteristic of the Preoperational Stage."},
  {id:"cald-149",d:"moderate",t:"Bandura's Social Cognitive Theory",q:"Bandura believed that TELEVISION was a source of behavior modeling. This is because TV serves as a:",c:["A. Real-life model","B. Representational model","C. Kinesthetic model","D. Symbolic model"],a:"B",e:"Representational models are presented through audio-visual measures or videos — television is a classic example of a representational model in Bandura's theory."},
  {id:"cald-150",d:"moderate",t:"Ausubel's Meaningful Learning",q:"Which of the following BEST distinguishes Ausubel's theory from Piaget's?",c:["A. Piaget focused on meaningful learning while Ausubel focused on stages","B. Ausubel focused on how school subjects are learned by school children, emphasizing prior knowledge as the primary determiner","C. Piaget believed learning is passive while Ausubel believed it is active","D. Ausubel proposed biological maturation stages; Piaget focused on prior knowledge"],a:"B",e:"Ausubel was a cognitive learning theorist focused on the learning of school subjects — he believed what the student already knows is the primary determiner of whether and what he/she learns next."},
  {id:"cald-151",d:"moderate",t:"Stages of Human Development",q:"Which statement is TRUE about the BABYHOOD STAGE (2 weeks to 2 years)?",c:["A. Babies are completely helpless and cannot form social attachments","B. It is characterized by increasing dependency as babies need more care","C. Babies are capable of establishing friendships during this stage","D. This is the longest of all developmental periods"],a:"C",e:"Babies are capable of establishing friendships during the Babyhood Stage — despite crying, cooing, babbling, and gesturing as pre-speech forms of communication."},
  {id:"cald-152",d:"moderate",t:"Principles of Development",q:"The statement 'Development is the product of maturation and learning — heredity and environment, genes and culture' reflects which principle?",c:["A. Development involves change","B. Development follows an orderly sequence","C. Development is the product of maturation and learning","D. The rate of development is unique in each individual"],a:"C",e:"Principle #5 states that Development is the product of maturation (heredity/nature) and learning (environment/nurture) — both genetics and culture play roles."},
  {id:"cald-153",d:"moderate",t:"Piaget vs. Vygotsky",q:"Which of the following statements CORRECTLY contrasts Piaget and Vygotsky's views on the role of language?",c:["A. Both theorists agreed that language drives cognitive development equally","B. Piaget stressed the role of language in cognitive development; Vygotsky did not","C. Piaget did not give much emphasis on language; Vygotsky stressed the role of language in cognitive development","D. Vygotsky believed language develops after cognition; Piaget believed it develops simultaneously"],a:"C",e:"Piaget did NOT give much emphasis on language; Vygotsky STRESSED the role of language in cognitive development — this is a key difference between the two theorists."},
  {id:"cald-154",d:"moderate",t:"Erikson's Psychosocial Theory",q:"The COMPULSIVENESS maladaptation in Erikson's Autonomy stage is characterized by:",c:["A. Total inability to trust anyone — paranoia and psychosis","B. Feels as if everything must be done perfectly and mistakes must be avoided at all costs","C. The belief that his/her way is the only way","D. Being overly trusting and gullible"],a:"B",e:"Compulsiveness (maladaptation of Autonomy stage) — feels as if everything must be done perfectly; mistakes must be avoided at all costs."},
  {id:"cald-155",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"Bronfenbrenner's theory was originally called Ecological Theory but was later renamed:",c:["A. Sociocultural Theory","B. Bioecological Systems Theory","C. Psychosocial Ecological Theory","D. Human Development Ecological Framework"],a:"B",e:"Bronfenbrenner's theory was renamed the Bioecological Systems Theory — emphasizing that a child's own biology is a primary environment fueling her development."},
  {id:"cald-156",d:"moderate",t:"Information Processing Theory",q:"LATERAL TRANSFER in learning occurs when:",c:["A. A person learns more complex skills based on simpler prior learning","B. A person applies a specific skill in a similar situation","C. A person is able to perform a new task about the same level of complexity","D. A person applies general principles to dissimilar situations"],a:"C",e:"Lateral Transfer occurs when the individual is able to perform a new task about the same level as an already-learned task — transferring at the same level of complexity."},
  {id:"cald-157",d:"moderate",t:"Robert Gagne",q:"Gagne argued that effective instruction must go beyond traditional learning theories (behaviorism, cognitivism, constructivism) and provide support to transition from:",c:["A. Observation to practice to mastery","B. Simple to complex skills using a hierarchical model","C. Memorization to application to analysis","D. External motivation to internal motivation"],a:"B",e:"Gagne argued that effective instruction must reach beyond traditional theories and provide support to transition from simple to complex skills, using a hierarchical model for learning."},
  {id:"cald-158",d:"moderate",t:"Operant Conditioning",q:"Which of the following CORRECTLY distinguishes Negative Reinforcement from Negative Punishment?",c:["A. Both increase a behavior; the difference is whether something is added or removed","B. Negative Reinforcement increases behavior by removing something negative; Negative Punishment decreases behavior by removing something positive","C. Negative Reinforcement decreases behavior; Negative Punishment increases behavior","D. Both decrease behavior; the difference is whether the stimulus is positive or negative"],a:"B",e:"Negative Reinforcement: REMOVES something NEGATIVE → INCREASES behavior. Negative Punishment: REMOVES something POSITIVE → DECREASES behavior."},
  {id:"cald-159",d:"moderate",t:"Stages of Human Development",q:"The MIDDLE AND LATE CHILDHOOD stage (6-12 years) is also called:",c:["A. The Preschooler Years","B. The Adolescent Period","C. The Gang and Creativity Age","D. The Period of Extreme Helplessness"],a:"C",e:"Middle and Late Childhood (6-12 years) is called the Gang and Creativity Age — when self-help skills, social skills, school skills, and play skills are developed."},
  {id:"cald-160",d:"moderate",t:"Metacognition",q:"Task Variables in metacognition refer to:",c:["A. Knowledge about how human beings learn and process information","B. Awareness of the strategy you are using to learn a topic","C. Knowledge about the nature of the task and the type of processing demands it places on the individual","D. Awareness of memory strategies that work best for you"],a:"C",e:"Task Variables include knowledge about the nature of the task as well as the type of processing demands that it will place upon the individual."},

  // ==================== DIFFICULT (40) ====================
  {id:"cald-161",d:"difficult",t:"Integrated Theories",q:"A teacher uses cooperative learning groups (Vygotsky's ZPD), provides feedback after performance (Gagne's Event 7), and adjusts tasks based on observed schemas (Piaget). Which theoretical integration BEST describes this teaching approach?",c:["A. Pure Behaviorism — focusing only on observable behavior and reinforcement","B. Eclectic approach — drawing from multiple learning theories simultaneously","C. Humanistic approach — focusing primarily on self-actualization","D. Psychoanalytic approach — addressing unconscious conflicts"],a:"B",e:"The teacher is using an eclectic approach — intentionally drawing from multiple theoretical frameworks (Vygotsky, Gagne, Piaget) simultaneously to maximize learning effectiveness."},
  {id:"cald-162",d:"difficult",t:"Erikson vs. Freud",q:"Both Freud and Erikson proposed stage theories of development. The MOST significant difference between the two is that Erikson:",c:["A. Focused exclusively on the first five years of life as Freud did","B. Ignored the role of the unconscious in personality development","C. Extended development across the entire lifespan and emphasized social/cultural factors, not just sexuality","D. Rejected the idea that early experiences influence later development"],a:"C",e:"Erikson extended development across the entire lifespan (8 stages from birth to death) and emphasized psychosocial/social-cultural factors — not just sexual development as Freud emphasized."},
  {id:"cald-163",d:"difficult",t:"Piaget's Cognitive Development",q:"A researcher presents a child with the following syllogism: 'All roses are flowers. All flowers are plants. Are all roses plants?' A child who can answer correctly without seeing actual roses or plants is demonstrating:",c:["A. Concrete Operational reasoning with Seriation","B. Preoperational Symbolic Function","C. Formal Operational Hypothetical-Deductive and Abstract Reasoning","D. Sensorimotor Object Permanence"],a:"C",e:"This syllogism requires abstract reasoning (no concrete objects present) and deductive logic — hallmarks of Formal Operational Stage. Younger children need concrete objects to reason."},
  {id:"cald-164",d:"difficult",t:"Vygotsky and Behaviorism",q:"A teacher says 'I do, you watch' while modeling a skill, then 'I do, you help' for guided practice. From a COMBINED Vygotsky-Gagne perspective, what is the teacher primarily doing?",c:["A. Using classical conditioning to pair learning with positive stimuli","B. Moving the learner through the ZPD via scaffolding while following Gagne's hierarchical instructional events","C. Applying Ausubel's advance organizers to activate prior knowledge","D. Implementing Bandura's motor reproduction phase through operant conditioning"],a:"B",e:"The teacher is using scaffolding (ZPD, Vygotsky) to gradually withdraw support while simultaneously following Gagne's hierarchical instruction — a ZPD+Gagne integration."},
  {id:"cald-165",d:"difficult",t:"Kohlberg's Moral Development",q:"A whistleblower exposes her company's illegal dumping of toxic waste, knowing she will be fired and face legal threats. She acts because she believes exposing injustice is morally right, regardless of personal consequences. Kohlberg would MOST likely classify her moral reasoning at:",c:["A. Stage 3 — Good Girl Orientation (seeking social approval)","B. Stage 4 — Law and Order (following legal duties)","C. Stage 5 — Social Contract (protecting society's best interests)","D. Stage 6 — Universal Ethical Principle (acting on conscience and universal principles)"],a:"D",e:"Stage 6 — she acts on self-chosen ethical principles (exposing injustice is right) in accord with logical comprehensiveness, universality, and consistency — regardless of personal cost."},
  {id:"cald-166",d:"difficult",t:"Piaget's Cognitive Development",q:"Which combination of cognitive characteristics would MOST ACCURATELY describe a child in the LATE PREOPERATIONAL stage transitioning toward Concrete Operational thinking?",c:["A. Full conservation, abstract reasoning, and deductive logic","B. Object permanence, reflexive behavior, and muscle movement","C. Beginning decentering, emerging reversibility, and some conservation skills alongside residual egocentrism","D. Hypothetical thinking, seriation, and formal logical operations"],a:"C",e:"At the transition point, children begin decentering and developing reversibility and some conservation skills while still showing residual egocentrism from the Preoperational Stage."},
  {id:"cald-167",d:"difficult",t:"Integrated Theories",q:"The statement 'What the student already knows is the primary determiner of whether and what he/she learns next' (Ausubel) is MOST consistent with which other theoretical construct?",c:["A. Skinner's principle that behavior is shaped by consequences","B. Piaget's schema and the process of assimilation — fitting new information into existing knowledge structures","C. Vygotsky's ZPD — the gap between actual and potential development","D. Freud's principle that unconscious conflicts determine behavior"],a:"B",e:"Ausubel's emphasis on prior knowledge as the primary determiner is most consistent with Piaget's schema and assimilation — both theorists emphasize existing cognitive structures as the foundation for new learning."},
  {id:"cald-168",d:"difficult",t:"Erikson's Psychosocial Theory",q:"A person who successfully resolves ALL eight of Erikson's psychosocial crises would possess which combination of virtues?",c:["A. Hope, Will, Purpose, Competency, Fidelity, Love, Caring, Wisdom","B. Trust, Autonomy, Initiative, Industry, Identity, Intimacy, Generativity, Integrity","C. Assimilation, Accommodation, Equilibration, Conservation, Seriation, Decentering, Reversibility, Formal Operations","D. Oral, Anal, Phallic, Latency, Genital, Preconventional, Conventional, Postconventional"],a:"A",e:"The eight virtues gained from resolving each of Erikson's stages: Hope, Will/Determination, Purpose/Courage, Competency, Fidelity, Love, Caring, Wisdom."},
  {id:"cald-169",d:"difficult",t:"Bronfenbrenner and Policy",q:"A government passes legislation requiring all schools to provide inclusive education for learners with disabilities. A child with autism benefits from this policy. Tracing the FULL ecological path of this influence on the child, the sequence would be:",c:["A. Microsystem → Mesosystem → Exosystem → Child","B. Macrosystem (law) → Exosystem (DepEd policy) → Mesosystem (school-family communication) → Microsystem (inclusive classroom) → Child","C. Chronosystem → Macrosystem → Child directly","D. Exosystem → Microsystem → Child directly, bypassing all other systems"],a:"B",e:"The full ecological path: Macrosystem (cultural law) → Exosystem (DepEd/government policy) → Mesosystem (how school and family work together) → Microsystem (inclusive classroom) → Child."},
  {id:"cald-170",d:"difficult",t:"Metacognition and Learning",q:"A student who says 'I know that I learn better by making connections to things I already know, so I always create concept maps before studying a new chapter' is demonstrating all THREE categories of metacognitive knowledge. Which option CORRECTLY maps the statement to all three categories?",c:["A. Person Variables only — self-knowledge about learning style","B. Task Variables only — understanding the nature of concept mapping","C. Strategy Variables only — choosing an effective strategy","D. Person Variables (I learn better through connections), Task Variables (studying a new chapter requires connecting to prior knowledge), and Strategy Variables (using concept maps as an effective strategy)"],a:"D",e:"All three metacognitive categories are present: Person Variables (I know how I learn), Task Variables (understanding what the task demands), and Strategy Variables (using and evaluating concept maps)."},
  {id:"cald-171",d:"difficult",t:"Freud's Psychoanalytic Theory",q:"Freud's TOPOGRAPHICAL MODEL distinguishes between the Unconscious, Conscious, and Subconscious. A therapist discovers that a client's extreme rage toward authority figures stems from a deeply buried memory of parental abuse that the client has no awareness of. This memory is stored in the:",c:["A. Conscious — all that the person is aware of","B. Preconscious/Subconscious — accessible when prompted","C. Unconscious — influences thoughts and behavior without awareness; buried to avoid extreme anxiety","D. Ego — the reality-based mediator of behavior"],a:"C",e:"The Unconscious contains all the things we don't know that affect our behavior — buried memories of parental abuse, stored to avoid extreme anxiety, influence behavior without conscious awareness."},
  {id:"cald-172",d:"difficult",t:"Kohlberg's Moral Development",q:"A person at Stage 5 (Social Contract) and a person at Stage 6 (Universal Ethical Principles) may BOTH break a law. What is the KEY distinction in their reasoning?",c:["A. Stage 5 breaks law for personal benefit; Stage 6 breaks law due to peer pressure","B. Stage 5 believes the law should be changed through democratic process; Stage 6 acts on conscience based on universal principles regardless of democratic consensus","C. Both have identical reasoning — they both prioritize society's best interests","D. Stage 6 is more likely to follow laws than Stage 5 because principles often align with laws"],a:"B",e:"Stage 5 seeks to change unjust laws through social contract and democratic process. Stage 6 acts based on self-chosen universal ethical principles (conscience) regardless of what any democratic process has decided."},
  {id:"cald-173",d:"difficult",t:"Integrated Theories",q:"A child prodigy plays piano concertos at age 5 far beyond what is typical. Which combination of factors BEST explains this from a holistic developmental perspective?",c:["A. Operant conditioning alone — positive reinforcement shaped the skill","B. Maturation alone — the child's biology predetermined the talent","C. The interaction of maturation (biological talent), learning (practice, instruction), and environmental factors (exposure, supportive family) — consistent with Principle #5 of development","D. Unconscious drives from Freud's Phallic Stage that manifested as musical expression"],a:"C",e:"Principle #5 — Development is the product of maturation AND learning: heredity (biological talent), environment (exposure, instruction, supportive family), and genes and culture all interact."},
  {id:"cald-174",d:"difficult",t:"Vygotsky's Socio-Cultural Theory",q:"Vygotsky believed that cognitive development is a SOCIALLY MEDIATED PROCESS. What does this mean for classroom instruction?",c:["A. Students should primarily learn through independent discovery without teacher interference","B. Teachers should avoid correcting students to prevent inhibiting natural development","C. Social interaction, language, and collaborative activity with MKOs are ESSENTIAL tools for cognitive growth — not mere supplements to individual learning","D. Biological maturation determines readiness; instruction should wait for natural readiness"],a:"C",e:"For Vygotsky, social interaction is not a supplement — it IS the primary mechanism of cognitive development. Instruction must actively use language, social interaction, and MKOs as tools for growth."},
  {id:"cald-175",d:"difficult",t:"Piaget's Cognitive Development",q:"A critic argues that Piaget UNDERESTIMATED children's cognitive abilities by using tasks that were linguistically complex and decontextualized. This criticism MOST directly challenges:",c:["A. The concept of Object Permanence in the Sensorimotor Stage","B. The age norms and sequence of Piaget's stages — children may reach stages earlier in familiar, simplified contexts","C. Vygotsky's ZPD as an alternative to Piaget's stages","D. Ausubel's theory of meaningful learning as applied to school subjects"],a:"B",e:"Critics argue that Piaget's complex, decontextualized tasks underestimated children's abilities — in familiar contexts with simpler language, children demonstrate cognitive skills earlier than Piaget predicted."},
  {id:"cald-176",d:"difficult",t:"Maslow and Education",q:"A teacher in a war-affected community finds that students cannot concentrate on lessons. According to Maslow's hierarchy, what is the MOST appropriate first step?",c:["A. Provide self-actualization opportunities through creative projects","B. Focus on academic content delivery as scheduled","C. Address students' unmet Safety and Physiological Needs FIRST before academic instruction","D. Increase esteem opportunities through recognition and awards"],a:"C",e:"Maslow's hierarchy requires that lower-order needs be met before higher-order needs. Students in a war zone have unmet Safety and even Physiological Needs — these MUST be addressed before academic learning can occur."},
  {id:"cald-177",d:"difficult",t:"Integrated Theories",q:"Thorndike's Law of Effect states that behaviors followed by satisfying consequences are strengthened. How does this RELATE to and DIFFER from Skinner's operant conditioning?",c:["A. They are identical — Thorndike and Skinner proposed the same theory independently","B. Thorndike's Law of Effect was the precursor to Skinner's operant conditioning; Skinner refined it by systematically categorizing reinforcement and punishment types","C. Thorndike focused on cognitive processes; Skinner focused on observable behavior","D. Thorndike rejected consequences as factors in learning; Skinner embraced them"],a:"B",e:"Thorndike's Law of Effect was the foundation (precursor) of Skinner's operant conditioning. Skinner built on this by systematically categorizing the types and schedules of reinforcement and punishment."},
  {id:"cald-178",d:"difficult",t:"Bronfenbrenner and Development",q:"A research study finds that children whose parents work long hours in stressful jobs show lower academic performance and higher anxiety — even though the children never experience the parents' workplace directly. This finding is BEST explained by:",c:["A. Microsystem influence — the child's immediate family interactions","B. Exosystem influence — the indirect impact of parental work stress on family dynamics, which then affects the child","C. Macrosystem influence — cultural beliefs about work and family","D. Chronosystem influence — historical changes in work patterns"],a:"B",e:"The Exosystem has an INDIRECT impact — the parents' stressful workplace affects family dynamics (Microsystem), which then affects the child. The child never directly experiences the workplace."},
  {id:"cald-179",d:"difficult",t:"Erikson's Psychosocial Theory",q:"A researcher studying 'third culture kids' — children raised between two or more cultures — finds that they often experience extended periods of identity searching. From Erikson's perspective, which of the following BEST explains this phenomenon?",c:["A. They have failed to resolve the Industry vs. Inferiority crisis and feel incompetent","B. The multiple cultural contexts create complex psychosocial environments that prolong and complicate the Identity vs. Role Confusion crisis","C. Their Microsystem (Bronfenbrenner) is too diverse to allow for proper Schema formation (Piaget)","D. They experience Moral Development at Stage 2 (Instrumental) because they seek personal benefit from each culture"],a:"B",e:"Multiple cultural contexts create complex, competing psychosocial demands during adolescence — third culture kids face a more complex Identity vs. Role Confusion crisis with multiple reference groups and cultural expectations."},
  {id:"cald-180",d:"difficult",t:"Integrated Theories",q:"A child learns to fear injections (classical conditioning), avoids hospitals to reduce anxiety (negative reinforcement), observes a nurse hero on TV and begins to admire medical workers (observational learning), and eventually enters nursing school because of intrinsic fulfillment (self-actualization). This developmental narrative BEST illustrates:",c:["A. The application of a single learning theory across all stages of life","B. The sequential and exclusive application of behaviorism at every stage","C. How multiple learning theories can apply to different aspects of the same person's behavioral and motivational development over time","D. Piaget's cognitive stages from Sensorimotor to Formal Operational"],a:"C",e:"Different learning theories apply to different aspects and stages of the person's development — Classical Conditioning, Operant Conditioning, Observational Learning (Bandura), and Humanistic (Maslow) theories all play a role."},
  {id:"cald-181",d:"difficult",t:"Piaget and Ausubel",q:"Piaget's Accommodation and Ausubel's Correlative Subsumption are SIMILAR in that both:",c:["A. Describe the process of fitting new information into existing schemas without change","B. Require the creation of entirely new knowledge structures unrelated to prior knowledge","C. Involve modifying or expanding existing cognitive structures to incorporate new, challenging information","D. Emphasize that learning is passive and occurs without conscious effort"],a:"C",e:"Both Accommodation (Piaget) and Correlative Subsumption (Ausubel) involve expanding or modifying existing cognitive structures when new, challenging information cannot be easily fitted in."},
  {id:"cald-182",d:"difficult",t:"Kohlberg and Gender",q:"Carol Gilligan criticized Kohlberg's theory for being gender-biased because Kohlberg's research:",c:["A. Excluded adult males from his moral development research","B. Used only female subjects, failing to represent male moral reasoning","C. Was based primarily on male subjects, leading to a justice-oriented framework that undervalued the care-oriented moral reasoning more common in females","D. Overrepresented Stage 6 in female subjects compared to males"],a:"C",e:"Gilligan argued that Kohlberg's research was based primarily on males, producing a justice-oriented framework that undervalued the care and relationship-oriented moral reasoning that is more common in women."},
  {id:"cald-183",d:"difficult",t:"Developmental Psychology",q:"The concept of CRITICAL PERIOD in development suggests that certain experiences must occur during a specific window of time for normal development to proceed. Which of the following is the BEST application of this concept for educators?",c:["A. Teachers should wait until children naturally reach readiness before providing instruction","B. Enriched environments, especially in early childhood, are crucial because early experiences form the foundation that shapes later development","C. Formal academic instruction should begin only in late childhood when the brain is fully developed","D. The quality of instruction in high school is more important than experiences in early childhood"],a:"B",e:"The Critical Period concept (Principle #4 — Early development is more critical) means educators must provide enriched, stimulating environments especially in early childhood, as these form the foundation for all future development."},
  {id:"cald-184",d:"difficult",t:"Integrated Theories",q:"A student from a low-income family struggles academically. Which theoretical framework provides the MOST COMPREHENSIVE explanation of the MULTIPLE factors affecting her development?",c:["A. Freud's Psychoanalytic Theory — her unconscious conflicts drive academic failure","B. Skinner's Operant Conditioning — she lacks positive reinforcement for academic behavior","C. Piaget's Cognitive Theory — she has not yet reached the Formal Operational Stage","D. Bronfenbrenner's Bioecological Systems Theory — interactions across Microsystem (family stress), Exosystem (parental employment), Macrosystem (poverty policy), and Chronosystem (historical inequality) all affect her development"],a:"D",e:"Bronfenbrenner's framework is the most comprehensive — it captures the multiple interacting systems (family, community, policy, culture, history) that all contribute to the student's academic struggles."},
  {id:"cald-185",d:"difficult",t:"Freud and Defense Mechanisms",q:"A student who fails a major exam suddenly develops intense interest in helping other students study. Freud would MOST likely interpret this as the defense mechanism of:",c:["A. Repression — pushing the failure into the unconscious","B. Projection — attributing the failure to others","C. Reaction Formation — converting failure anxiety into its opposite (helping others succeed)","D. Sublimation — channeling failure energy into academic productivity"],a:"D",e:"Sublimation — channeling the energy and anxiety from the failure into a socially productive activity (helping others study) is a classic example of sublimation as a defense mechanism."},
  {id:"cald-186",d:"difficult",t:"Vygotsky and Piaget",q:"Piaget believed that language is a PRODUCT of cognitive development. Vygotsky believed language is a TOOL that DRIVES cognitive development. What is the EDUCATIONAL IMPLICATION of Vygotsky's position?",c:["A. Teachers should avoid using language-heavy instruction until students have reached the appropriate cognitive stage","B. Language-rich classroom environments — discussion, dialogue, and collaborative talk — are essential instructional tools, not just communication vehicles","C. Students should develop cognitive skills independently before language instruction begins","D. Reading and writing should be delayed until the Concrete Operational Stage is reached"],a:"B",e:"If language drives cognitive development (Vygotsky), then language-rich classrooms — with rich discussion, dialogue, and collaborative talk — are essential instructional tools for promoting cognitive growth."},
  {id:"cald-187",d:"difficult",t:"Piaget's Cognitive Development",q:"A teacher argues that 'readiness' should determine when content is taught. Piaget's theory SUPPORTS this view, but Vygotsky's theory CHALLENGES it because:",c:["A. Piaget believed teaching above a child's stage is harmful; Vygotsky believed teaching WITHIN the ZPD (slightly above current ability) with scaffolding actually DRIVES development forward","B. Piaget believed instruction should begin before biological readiness; Vygotsky disagreed","C. Both theorists agreed that readiness determines when instruction should begin","D. Vygotsky believed readiness is entirely biologically determined; Piaget believed it is socially determined"],a:"A",e:"Piaget: wait for natural readiness (stage determines when to teach). Vygotsky: instruction WITHIN the ZPD — slightly above current ability — with scaffolding is what CREATES development, not waits for it."},
  {id:"cald-188",d:"difficult",t:"Maslow and Motivation",q:"A student has all physiological, safety, and belonging needs met, yet still lacks motivation in class. According to Maslow, the MOST LIKELY explanation is:",c:["A. Unmet Physiological Needs are causing hidden stress","B. A Safety Need is threatened by academic competition","C. Unmet Esteem Needs — lack of recognition, competence, or self-confidence in the academic setting","D. The student has already reached Self-Actualization and needs no further motivation"],a:"C",e:"When lower-order needs are met but motivation is still lacking, Maslow points to Esteem Needs — the need for recognition, competence, mastery, and self-confidence in the specific domain."},
  {id:"cald-189",d:"difficult",t:"Integrated Theories",q:"A teacher notices that a student can recite Kohlberg's stages correctly (cognitive knowledge) but consistently cheats on tests (behavior). This discrepancy BEST illustrates:",c:["A. Kohlberg's theory is invalid and does not describe real moral reasoning","B. The difference between moral knowledge and moral action — knowing stages cognitively does not guarantee behavior at those stages","C. The student is at Stage 1 and cannot understand higher stages","D. Bandura's Social Cognitive Theory has replaced Kohlberg as a better explanation of moral behavior"],a:"B",e:"Knowing moral stages cognitively does not guarantee acting at those stages — this illustrates the well-documented gap between moral reasoning (knowledge) and moral action (behavior)."},
  {id:"cald-190",d:"difficult",t:"Erikson and Education",q:"Erikson's Industry vs. Inferiority stage (elementary school years) has the MOST DIRECT implication for which educational practice?",c:["A. Creating a trauma-informed classroom that addresses early attachment issues","B. Providing students with meaningful tasks at appropriate challenge levels, celebrating mastery to build competence and avoid learned helplessness","C. Allowing complete freedom in task choice to resolve Initiative vs. Guilt","D. Delaying academic instruction until Identity is formed in adolescence"],a:"B",e:"Industry vs. Inferiority — students need meaningful, achievable tasks with recognition of competence to develop Industry. Repeated failure or inappropriate tasks lead to Inferiority and learned helplessness."},
  {id:"cald-191",d:"difficult",t:"Piaget's Cognitive Development",q:"EQUILIBRATION — achieving proper balance between assimilation and accommodation — is Piaget's explanation for:",c:["A. The passive reception of knowledge from the environment","B. The biological maturation process that determines cognitive readiness","C. The self-regulatory mechanism that drives cognitive growth toward increasingly sophisticated schemas","D. The social interaction that builds knowledge through language and collaboration"],a:"C",e:"Equilibration is Piaget's self-regulatory mechanism — when existing schemas fail to explain new experiences (disequilibrium), the child is motivated to assimilate or accommodate, driving cognitive growth."},
  {id:"cald-192",d:"difficult",t:"Bronfenbrenner and Chronosystem",q:"A child born in 1950 and a child born in 2000 grow up in the same town with identical family structures. Yet they differ significantly in their use of technology, cultural attitudes toward gender roles, and exposure to global events. Which system PRIMARILY explains these differences?",c:["A. Microsystem — differences in immediate family structure","B. Mesosystem — differences in teacher-parent relationships","C. Exosystem — differences in parental employment opportunities","D. Chronosystem — the different historical and social time periods in which they grew up"],a:"D",e:"The Chronosystem — the social and historical time frame in which a child's life is set — is the primary explanation. The same town, family structure, but different historical periods (1950 vs. 2000) produce very different developmental contexts."},
  {id:"cald-193",d:"difficult",t:"Integrated Theories",q:"A child who was abused in early childhood (Freud's critical period / Principle #4) struggles with trust (Erikson's Stage 1), cannot regulate emotions in social settings (Social/Emotional Domain), and has difficulty forming schemas for safe relationships (Piaget). This case BEST illustrates:",c:["A. How a single theory (Freud) is sufficient to explain complex developmental outcomes","B. How early trauma has cascading effects across multiple theoretical domains simultaneously","C. That developmental theories are mutually exclusive and should not be combined","D. That the Macrosystem (Bronfenbrenner) is the sole cause of developmental trauma"],a:"B",e:"Early trauma has cascading, cross-theoretical effects — it simultaneously impacts psychosexual development (Freud), psychosocial trust (Erikson), social-emotional development, and cognitive schema formation (Piaget)."},
  {id:"cald-194",d:"difficult",t:"Vygotsky and Language",q:"A child narrates her own actions aloud while playing ('now I put the block here, then I stack it'). Vygotsky would interpret this Private Speech as:",c:["A. A sign of egocentrism and inability to take others' perspectives (Piaget's view)","B. An early indicator of language disorder that should be corrected","C. A transitional tool — social speech being internalized as a cognitive tool for self-regulation and thought","D. An example of Bandura's self-reinforcement mechanism"],a:"C",e:"Vygotsky viewed Private Speech as social speech being internalized — a transitional tool from social communication to internal thought and self-regulation. It is a sign of healthy cognitive development."},
  {id:"cald-195",d:"difficult",t:"Kohlberg and Moral Education",q:"A school implements a 'Just Community' approach — democratic governance of the school, community moral discussions, and collective decision-making. This approach is MOST consistent with which moral development framework?",c:["A. Freud's Psychoanalytic Theory — resolving unconscious moral conflicts through group therapy","B. Skinner's Operant Conditioning — using collective reinforcement for moral behavior","C. Kohlberg's Post-Conventional Morality — fostering the development of Stage 5 (Social Contract) and Stage 6 (Universal Ethical Principles) through democratic practice","D. Erikson's Identity vs. Role Confusion — helping students find their moral identity"],a:"C",e:"Kohlberg's 'Just Community' approach was his own educational application — using democratic school governance to foster Post-Conventional moral reasoning (Stages 5 and 6)."},
  {id:"cald-196",d:"difficult",t:"Piaget and Constructivism",q:"Piaget's theory is often called CONSTRUCTIVISM because it proposes that:",c:["A. Knowledge is transmitted directly from teacher to student through clear explanation","B. Children passively absorb knowledge from their environment","C. Children ACTIVELY construct knowledge through their interactions with the environment, not passively receive it","D. Knowledge is genetically pre-programmed and unfolds through biological maturation alone"],a:"C",e:"Piaget's Constructivism — children are not passive receivers of knowledge. They actively CONSTRUCT knowledge through their interactions with the environment, through assimilation, accommodation, and equilibration."},
  {id:"cald-197",d:"difficult",t:"Maslow and Self-Actualization",q:"Maslow described Self-Actualization as qualitatively different from the other four needs because:",c:["A. It is the easiest need to satisfy and the most basic of all human needs","B. Unlike deficiency needs (D-needs), Self-Actualization is a growth need (B-need) — satisfying it increases rather than reduces the desire for more growth","C. It does not motivate behavior the way physiological and safety needs do","D. It can be achieved without first satisfying any of the lower-level needs"],a:"B",e:"Self-Actualization is a Being/Growth Need (B-need) — unlike Deficiency Needs (D-needs) which are reduced when satisfied, growth needs INCREASE motivation the more they are fulfilled."},
  {id:"cald-198",d:"difficult",t:"Integrated Theories",q:"The principle 'Development involves change — physical, emotional, and mental' (Principle #3) combined with Bronfenbrenner's bioecological framework suggests that educators should:",c:["A. Focus only on cognitive development since it is most measurable","B. Address development in isolated domains — physical in PE, emotional in counseling, cognitive in academics","C. Recognize that all developmental domains interact within ecological contexts — holistic, integrated, and ecological approaches to education are most effective","D. Prioritize the Macrosystem (policy) over Microsystem (classroom) factors in educational planning"],a:"C",e:"Development involves ALL domains changing simultaneously (Principle #3) within ecological contexts (Bronfenbrenner) — educators need holistic, integrated, ecologically-sensitive approaches that address the whole child."},
  {id:"cald-199",d:"difficult",t:"Freud and Erikson Integration",q:"Both Freud's Phallic Stage and Erikson's Initiative vs. Guilt stage occur during the SAME developmental period (ages 3-6). What does this parallel suggest about preschool-age children?",c:["A. Preschool children's development is primarily determined by unconscious sexual drives only","B. This age is a critical convergence period — children are simultaneously developing gender identity, resolving family relationship dynamics, AND developing a sense of purposeful action and self-direction","C. Erikson's and Freud's theories contradict each other at this stage and cannot both be valid","D. Initiative is more important than resolving the Oedipus/Electra Complex at this stage"],a:"B",e:"The parallel between Freud's Phallic Stage and Erikson's Initiative vs. Guilt suggests preschool is a critical convergence period — children simultaneously work through family relationship dynamics (Freud) while developing purposeful initiative (Erikson)."},
  {id:"cald-200",d:"difficult",t:"Integrated Theories",q:"A developmental psychologist argues that nature AND nurture are inseparable in human development. Which combination of theoretical evidence BEST supports this 'interactionist' position?",c:["A. Freud's stages (nature) vs. Behaviorism (nurture) — showing they are completely opposing views","B. Piaget's maturational readiness (nature) + Vygotsky's social learning (nurture) + Principle #5 (development = maturation × learning) — all converge on the inseparability of nature and nurture","C. Kohlberg's stages (nature) vs. Bandura's modeling (nurture) — showing they apply to different behaviors","D. Erikson's psychosocial stages (purely nurture) + Maslow's needs (purely nature) — both showing environmental factors"],a:"B",e:"Piaget's biological readiness (nature), Vygotsky's social/cultural environment (nurture), and Principle #5 (development = maturation × learning) all converge on the interactionist position that nature and nurture are inseparable."},
];
